INSERT INTO "public"."games_catalog" ("id", "name", "description", "cover_url", "release_date", "genre", "brand", "rating", "igdb_id", "quantity", "price", "age_rating", "artworks", "screenshots", "similar_games", "videos", "involved_companies", "game_type", "dlcs", "collections") VALUES (808, 'Silly Survivors', 'Silly Survivors - a casual, pared-down roguelike where you play as an adorable but fiercely determined furry fox, armed with… a flashlight! Your mission is simple: survive waves of suspiciously silly ghosts who keep trying to get close (and pull some kind of silly stuff). Light is your main weapon.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaw90.jpg', '2025-10-31', '{32}', 'IGDB', 100, 376092, 1, 83.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/222809.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/222810.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1710168.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1710176.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1710179.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1710169.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1710178.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1710170.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1710171.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1710172.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1710173.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1710174.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1710175.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1710177.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1714369.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1714370.jpg"]', '{113895,105233,111130,32902,119121,40524,106987,37419,28309,43367}', '{}', null, '0', null, null), (809, 'Ghost Town', 'Ghost Town is a single player VR puzzle-adventure from the makers of The Room. London, 1983. Edith Penrose is a ghost hunter, busy exorcising her way through the city''s restless spirits. But after her brother goes missing Edith must draw upon her wits & supernatural talents to unravel the mystery.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9isx.jpg', '2025-04-24', '{9,31}', 'IGDB', 100, 335127, 1, 86.99, '[{"id":219742,"rating_category":{"id":5,"rating":"T"}},{"id":230224,"rating_category":{"id":10,"rating":"12"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/156373.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1479255.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1479256.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1479257.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1479258.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1479259.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1479260.jpg"]', '{27266,27725,26223,25646,25222,96200,81275,106992,18011,95776}', '{https://www.youtube.com/watch?v=1RgXEHsnAOg,https://www.youtube.com/watch?v=0LxH7FtHlo8}', 'Fireproof Games', '0', null, null), (810, 'Oxide: Survival Island', 'OXIDE is a mobile multiplayer survival simulator. Players must survive on a deserted island by gathering resources, building bases, crafting weapons, and battling other players, hunger, and wild animals.

Become part of a vast, living world where social interaction is more vital than any guide. Form powerful clans, storm enemy bases, or survive in the shadows, delivering precision strikes. In this game, there are no limits to betrayal or heroism. It’s just you, your craft, and endless real-time PvP.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobc49.jpg', '2025-04-18', '{5,12,13}', 'IGDB', 100, 330539, 1, 86.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1742309.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1742307.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1742308.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1742310.jpg"]', '{26574,17379,44076,37419,17548,19164,19564,10776,109339,15536}', '{https://www.youtube.com/watch?v=3s2IraNbvfA,https://www.youtube.com/watch?v=mZpvqFTlznE}', 'Hyperhug', '0', null, null), (811, 'Rooftop Rascal: The Claus Cat', 'In "Rooftop Rascal: The Claus Cat," take control of a nimble cat scaling fire escapes and rooftops in a Christimas-themed adventure. Test your quick thinking and jumping skills as you climb higher and higher to reach the rooftop.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coam4l.jpg', '2025-01-16', null, 'IGDB', 100, 328386, 1, 90.99, '[{"id":196045,"rating_category":{"id":3,"rating":"E"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/152456.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/152457.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1450787.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1450788.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1450785.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1450786.jpg"]', null, '{}', 'chroda.eu', '0', null, '{12821}'), (812, 'Fatal Fury: City of the Wolves - Special Edition', 'After 26 years, FATAL FURY is back!

