1483,44719}', '{}', null, '0', null, null), (825, 'Trailer Park King', 'He''s a gamer, a bootlegger, a photographer and a connoisseur of the ladies! Can you juggle all the responsibilities and become the Trailer Park King?', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobovg.jpg', '2011-07-29', '{2,31}', 'IGDB', 100, 65755, 1, 15.99, '[]', '[]', '[]', '{13189,25222,27725,19164,81275,11367,18011,236,18841,61}', '{}', 'Freelance Games', '0', null, '{3379}'), (826, 'Motor City Online', 'In this online-only game, you buy classic cars, customize their performance to your liking, and race them against opponents around the world. The game was plagued with technical issues and met its end in August 29th 2003.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7u2d.jpg', '2001-10-29', '{10}', 'IGDB', 100, 23809, 1, 22.99, '[{"id":18697,"rating_category":{"id":3,"rating":"E"}}]', '[]', '[]', '{27553,10965,2074,96,78511,97,69052,60307,109292,105}', '{}', 'EA Seattle', '0', null, null), (827, 'Tony Hawk''s Pro Skater 4 Street', 'The mobile phone version of Tony Hawk''s Pro Skater 4.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ss9.jpg', '2002-12-31', null, 'IGDB', 100, 23754, 1, 27.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/335403.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/335404.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/335405.jpg"]', null, '{}', null, '11', null, '{5187}'), (828, 'EverQuest: Evolution', 'contains the original EverQuest game with all expansions available up to EverQuest: The Legacy of Ykesha', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1h68.jpg', '2003-08-25', '{12}', 'IGDB', 100, 23746, 1, 7.99, '[]', '[]', '[]', '{23651,49414,113910,69007,22790,19127,57033,19404,113636,54775}', '{}', null, '3', null, null), (831, 'Saints Row IV: Super Dangerous Wad Wad Edition (aka the Million Dollar Pack)', 'Deep Silver today unveils a very special edition of Saints Row IV. The Super Dangerous Wad Wad Edition aka The Million Dollar Pack will contain a selection of very Presidential items and activities for the ultimate Saints Row experience.

One Saints Row fan will be able to purchase this limited edition package which contains:

Saints Row IV : Commander in Chief Edition
A full sized replica Dubstep Gun
A full day of spy training
A trip to space with Virgin Galactic
One year’s membership of E25 Super Car Club and a Lamborghini Gallardo to make it worthwhile
Plastic Surgery of the purchaser’s choice
A shopping spree with a personal shopper to create the ultimate Planet Saints capsule wardrobe
7 nights for two at The Jefferson Hotel in Washington
Hostage rescue experience
A brand new Toyota Prius and insurance to give something back to the environment
7 nights stay in the Top Royal Suite at the Burj-al-arab with flights for two

The Super Dangerous Wad Wad Edition is available for pre-order through Game only, and will be delivered to the purchaser in a truly Presidential style.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8jd4.jpg', '2013-08-20', '{5,31}', 'IGDB', 100, 21862, 1, 20.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/128888.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1357330.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1357331.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1357332.jpg"]', '{19164,55038,105269,105011,107318,103301,26574,47823,37419,110798}', '{}', 'Koch Media', '0', null, '{197}'), (832, 'Challenge Me: Math Workout', 'A brain training game for the Nintendo DS.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/uk890iuq1sucjenv3ps6.jpg', null, null, 'IGDB', 100, 21639, 1, 79.99, '[{"id":71670,"rating_category":{"id":3,"rating":"E"}}]', '[]', '[]', '{380828,316954,310971,242812,78996,15605,326900,291996,291994,291993}', '{}', null, '0', null, '{2325}'), (834, 'Destiny: The Taken King - Legendary Edition', 'Destiny: The Taken King Legendary Edition features the complete Destiny experience including The Taken King, the next great Destiny adventure, Destiny, Expansion I: The Dark Below and Expansion II: House of Wolves. Unite with 20 million Guardians in the fight to defend our universe and Become Legend.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co30dq.jpg', '2015-09-15', '{5,12}', 'IGDB', 100, 20860, 1, 10.99, '[{"id":36376,"rating_category":{"id":11,"rating":"16"}},{"id":188313,"rating_category":{"id":5,"rating":"T"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/11292.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/11289.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/11290.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/11291.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/28280.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/408090.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/408089.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/446672.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/446671.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/446670.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/446669.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/446668.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/446676.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/446675.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/446674.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/446673.jpg"]', '{105269,55038,107318,119177,68287,106805,38030,19164,36950,25311}', '{https://www.youtube.com/watch?v=z0cLeSgtm94}', 'Bungie', '3', null, null), (835, 'Rocket Riot', 'Get ready for Rocket Riot, an action-packed, side-scrolling, 8-bit shooter where the rockets and the fun never stops! With over 200 levels and over 300 characters, blowing things up has just reached a new level of awesome!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/eybxknbmnu2wegshdn5k.jpg', '2009-06-17', '{5,14,32,33}', 'IGDB', 100, 20479, 1, 7.99, '[{"id":18019,"rating_category":{"id":4,"rating":"E10+"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/55677.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/57196.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/57198.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/57199.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/57200.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/57197.jpg"]', '{15851,56033,43367,19164,17449,114287,3772,105269,55190,11646}', '{}', 'Codeglue', '0', null, null), (836, '3D Starstrike', '3D Starstrike is a clone of the original wireframe Star Wars game.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/xbuk7hef2t9uxhi9sltn.jpg', '1984-12-31', '{5,33}', 'IGDB', 100, 13271, 1, 11.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1401273.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1401274.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1401275.jpg"]', '{43367,105269,55038,68286,113362,107318,103301,306,111846,12539}', '{https://www.youtube.com/watch?v=Ux6KaB6h_Qg}', 'Realtime Games Software Ltd.', '0', null, '{2699}'), (837, 'Starquake', 'You are a BLOB (a Bio-Logically Operated Being) and are sent into the core of a planet in order to prevent dit from blowing up.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/ul5wwtyyqzh06j98agmx.jpg', '1985-10-03', '{8,9,33}', 'IGDB', 100, 12479, 1, 17.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/16767.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/974399.jpg"]', '{28070,56033,110503,20342,55173,24426,25905,12539,55190,90788}', '{https://www.youtube.com/watch?v=TY6n71roCXY}', 'Mandarin Software', '0', null, null), (838, 'Trainz Railroad Simulator 2004', 'In this 3D railroad simulator, you can operate locomotives from the golden age of steam to the modern present in realistic scenarios, to move goods and resources from one place to another and keep the wheels of industry turning. You are in charge of every aspect of the process: complete control over the orders of the drivers, limits for the transportation process, the movement of the passengers and freight and a custom scripted system to create your own rules.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8hk5.jpg', '2003-12-31', '{13}', 'IGDB', 100, 11013, 1, 24.99, '[{"id":18513,"rating_category":{"id":8,"rating":"3"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/297078.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/297076.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/297077.jpg"]', '{101573,105264,115738,17613,44178,112754,100794,36346,65827,76340}', '{}', 'FIP Publishing', '0', null, '{196}'), (839, 'Droplitz', 'Immerse yourself in an addictive puzzler that''s all about strategically twisting and connecting mismatched dials to save precious Droplitz. Just making a single junction is child''s play. Can you master the art of the combo, or will you let your pipes runneth over? Be warned! Losing too many droplitz can be hazardous to your ability to win. With four unique play modes, a variety of board sizes, and infinite replayability, Droplitz promises to drain all your time away.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co60js.jpg', '2009-06-24', '{9}', 'IGDB', 100, 10250, 1, 25.99, '[{"id":17403,"rating_category":{"id":3,"rating":"E"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/27653.jpg"]', '{28113,33153,19082,16992,7350,17130,11646,55190,18167,55173}', '{https://www.youtube.com/watch?v=x8IWGyXmyeA}', 'Blitz Arcade', '0', null, '{4287}'), (840, 'Robotron X', 'The arcade classic is taken to the next level, this time in 3D. The super-enhanced hero Ugene is once again called into action to save the last human family against the hordes of relentless Robotrons. Battle through 100 different levels, gaining new power-ups and abilities as Ugene survives wave after wave of the unrelenting hordes. While Ugene may face the familiar Robotrons, there will be new additions and tricks that the killer robots will use against the last surviving human family. Ugene must protect them at all cost while racking up the highest possible score!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9p2m.jpg', '1996-11-30', '{5}', 'IGDB', 100, 9186, 1, 22.99, '[{"id":209119,"rating_category":{"id":20,"rating":"12"}},{"id":209120,"rating_category":{"id":34,"rating":"G"}},{"id":78895,"rating_category":{"id":5,"rating":"T"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/160916.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1509568.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1509569.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1509570.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1509571.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1509572.jpg"]', '{55038,105269,68286,107318,103301,39769,113362,68287,103292,77488}', '{https://www.youtube.com/watch?v=34ctOKN8YKM}', 'GT Interactive Software', '0', null, '{5070}'), (841, 'The Munchables', 'The player controls creatures of insatiable appetite, using their regurgitating prowess to consume an army of invading Tabemon Space Pirates, each of whom bears an uncanny resemblance to various foods.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co68vm.jpg', '2009-05-27', '{8}', 'IGDB', 100, 5024, 1, 29.99, '[{"id":70559,"rating_category":{"id":3,"rating":"E"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1965.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1967.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1966.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1962.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1963.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1964.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1969.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1968.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/32900.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/32901.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/32902.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/32903.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/176467.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/176468.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/176470.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/176472.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/176469.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/176471.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/176473.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/176474.jpg"]', '{19164,20342,118313,24426,55173,55190,28070,56033,81183,89597}', '{}', 'Namco Bandai Games', '0', null, null), (842, 'Indianapolis 500 Legends', 'Fight to the finish in a hand-built speed machine racing seven inches off the ground at nearly 180 mph through a moving minefield of crashes, spinning cars, rolling tires, and 32 rivals on the world''s most famous racetrack in Indianapolis 500 Legends, an arcade-style racing experience set in a dynamic era spanning 1961-1971. Players will experience the traditions, rivalries, terrifying speeds, jaw-dropping maneuvers and infamous events that characterized this historic period at the world-famous Indianapolis 500 race.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5alf.jpg', '2007-12-18', '{10}', 'IGDB', 100, 4933, 1, 23.99, '[{"id":66342,"rating_category":{"id":3,"rating":"E"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/27814.jpg"]', '{109292,44178,80441,79756,77121,73719,73422,73154,72624,69725}', '{}', 'Destineer', '0', null, null), (843, 'The Legend of Zelda: Tears of the Kingdom - Nintendo Switch 2 Edition', 'In this sequel to The Legend of Zelda: Breath of the Wild, you’ll decide your own path through the sprawling landscapes of Hyrule and the mysterious islands floating in the vast skies above. Can you harness the power of Link’s new abilities to fight back against the malevolent forces that threaten the kingdom?', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coav5n.jpg', '2025-06-05', '{9,31}', 'IGDB', 99.983827828575, 338073, 1, 82.99, '[{"id":222163,"rating_category":{"id":36,"rating":"M"}},{"id":208025,"rating_category":{"id":10,"rating":"12"}},{"id":208026,"rating_category":{"id":14,"rating":"B"}},{"id":209686,"rating_category":{"id":4,"rating":"E10+"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/166162.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1497463.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1497464.jpg"]', '{28070,19164,17548,55038,10776,81249,26574,24426,54548,105049}', '{https://www.youtube.com/watch?v=dmDD7JSfhcE}', 'Nintendo', '10', null, '{8988,106}'), (844, 'Arches', 'In this visual novel, boyfriends Cameron and Devon investigate the supposedly haunted ghost town of Echo in search of an explanation of its troubled past.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2x5e.jpg', '2024-10-07', '{32,34}', 'IGDB', 99.9689440993789, 145445, 1, 49.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/436898.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/436899.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/436900.jpg"]', '{28465,110737,115735,16309,36815,111130,41895,111833,43097,75797}', '{}', 'Echo Project', '0', null, '{6896}'), (845, 'Bubsy 3D: Bubsy Visits the James Turrell Retrospective', 'A web-based 3D experience and homage to both art and Bubsy.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2htw.jpg', '2013-10-04', '{8}', 'IGDB', 99.7322648776245, 62466, 1, 20.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/132304.jpg"]', '{20342,56033,10841,225008,336477,333709,328245,322697,322695,322594}', '{}', 'Arcane Kids', '0', null, null), (846, 'Blood on the Clocktower', 'Blood on the Clocktower is a game of murder and mystery, lies and logic, deduction and deception for five-to-twenty courageous players and one devious storyteller.

A social game played in person or online, seated in a circle, each player receives either a ‘good’ or ‘evil’ token with their unique character on it. Good players share information to solve the mystery whilst evil players lie about who they are and what they know. The good team wins if they can piece together their knowledge, trust each other, and execute the demon. The evil team wins if the demon can sow distrust, evade detection, and wipe out the village.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6q6z.jpg', '2022-08-30', '{12,15,32,35}', 'IGDB', 99.7242737567701, 256090, 1, 63.99, '[]', '[]', '[]', '{109339,19404,26574,26145,80916,17548,113402,25311,35994,27092}', '{https://www.youtube.com/watch?v=bPma07qBlNQ}', 'The Pandemonium Institute', '0', null, null), (847, 'Grand Theft Auto V: Story Mode', 'Grand Theft Auto V: Story Mode is an add-on for the standalone version of Grand Theft Auto Online. Players can experience the interwoven stories of Franklin, Michael, and Trevor across the sun-soaked metropolis of Los Santos and the backwoods'' countryside of Blaine County in greater detail than ever before with stunning all new levels of visual detail. The game shares the same San Andreas map, although set in 2013.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co66n7.jpg', '2022-03-15', '{5,33}', 'IGDB', 99.7142335435411, 239060, 1, 77.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1054840.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1054841.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1054842.jpg"]', '{43367,19164,117939,95340,37419,119493,119177,38030,106805,87622}', '{}', 'Rockstar Games', '2', null, '{847}'), (848, 'Flimbo''s Quest', 'Rescuing girlfriends is a pretty common challenge in older computer games - why can''t any of these ladies look after themselves? On this occasion Pearly has been kidnapped by Fransz Dandruff, so better make sure he''s hair today, gone tomorrow.

The gameplay is platform based, although the player may move down platforms as well as up to the next one. There are lots of baddies (drawn in a cutesy style) who need shooting and offer rewards. The seven levels are fairly short and linear.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co857b.jpg', '1990-12-31', '{8}', 'IGDB', 99.6908585919575, 12103, 1, 22.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/18254.jpg"]', '{120184,23651,49414,24426,37001,28070,383903,378556,347817,339041}', '{}', 'System 3 Software', '0', null, null), (849, 'Elden Ring: Shadow of the Erdtree Edition', 'The Shadow of the Erdtree Edition includes the base game and the Shadow of the Erdtree expansion.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co89kn.jpg', '2024-02-21', '{12,31}', 'IGDB', 99.685238728302, 287975, 1, 63.99, '[{"id":168344,"rating_category":{"id":26,"rating":"19+"}},{"id":168349,"rating_category":{"id":32,"rating":"16"}},{"id":168346,"rating_category":{"id":11,"rating":"16"}},{"id":168345,"rating_category":{"id":37,"rating":"MA 15+"}},{"id":168347,"rating_category":{"id":21,"rating":"16"}},{"id":168343,"rating_category":{"id":6,"rating":"M"}},{"id":168348,"rating_category":{"id":16,"rating":"D"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/129024.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1246199.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1246196.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1246200.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1246197.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1246193.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1246201.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1246195.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1246192.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1246194.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1246198.jpg"]', '{81249,19164,106987,96217,115653,55038,17548,105049,55199,103168}', '{}', 'FromSoftware', '3', null, null), (850, 'Tobal 2', 'The fighting system in Tobal 2 is the same as in the previous game. The player can freely navigate 3D fighting arenas under the condition that he or she faces the opponent. High, medium, and low attacks can be executed using assigned buttons. As in Tobal No. 1, the grappling and blocking system offers the player a variety of offensive and defensive maneuvers. A new unblockable fireball attack has been added for each character. Tobal 2 was released on the same day as Sony''s Dual Analog Controller in Japan, noted as the first game compatible with the peripheral. Graphically, the game features Gouraud shaded and higher-resolution character models compared to Tobal No. 1, but still runs at 60 frames per second.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2u6p.jpg', '1997-04-25', '{4,12,31,33}', 'IGDB', 99.6278147910075, 1662, 1, 12.99, '[{"id":193700,"rating_category":{"id":13,"rating":"A"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/424539.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/424540.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/424541.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/424542.jpg"]', '{55038,101608,106987,96217,81249,103369,19164,105269,25311,55199}', '{https://www.youtube.com/watch?v=2s_IaThK9NQ}', 'Square', '0', null, '{329}'), (851, 'Mass Effect: Genesis 2', 'Mass Effect: Genesis 2 is an "interactive backstory comic". It is an updated version of Mass Effect: Genesis, which was originally created for Mass Effect 2. Genesis 2 fills the role of Mass Effect and Mass Effect 2 for new players to the series, introducing them to the story of the first two games in the Mass Effect trilogy and allowing them to make some of the major plot decisions that players could make by playing through the previous games. The player is prompted to begin Genesis 2 after character creation, but using it is optional. There are two versions of the comic, one each for a male and female Commander Shepard.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5rwo.jpg', '2013-04-02', '{34}', 'IGDB', 99.6215027690801, 202313, 1, 23.99, '[{"id":90242,"rating_category":{"id":6,"rating":"M"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1047800.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1047801.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1047802.jpg"]', '{89550,62151,105269,55038,25311,68286,107318,103301,115283,113362}', '{}', 'BioWare', '1', null, '{25}'), (852, 'Grand Theft Auto V', 'A new generation of Grand Theft Auto V featuring a range of technical improvements, visual upgrades and performance enhancements to take full advantage of the latest hardware, making the game more beautiful and more responsive than ever.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co66nd.jpg', '2022-04-12', '{5,10,31}', 'IGDB', 99.5962104330524, 134709, 1, 51.99, '[{"id":211581,"rating_category":{"id":33,"rating":"18"}},{"id":211580,"rating_category":{"id":12,"rating":"18"}},{"id":126201,"rating_category":{"id":38,"rating":"R 18+"}},{"id":108449,"rating_category":{"id":26,"rating":"19+"}},{"id":126200,"rating_category":{"id":22,"rating":"18"}},{"id":83487,"rating_category":{"id":6,"rating":"M"}},{"id":93296,"rating_category":{"id":17,"rating":"Z"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/78910.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/779131.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/779130.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/780674.jpg"]', '{19164,105011,106805,87622,81249,103303,55038,105269,107318,103301}', '{https://www.youtube.com/watch?v=lHRuzARP9-U,https://www.youtube.com/watch?v=foUaOCzfIRU,https://www.youtube.com/watch?v=xQT-O1nMSBU}', 'Take-Two Interactive', '3', null, null), (853, 'Batman: Arkham Collection', 'Batman: Arkham Collection includes the definitive versions of Rocksteady''s Arkham Trilogy games, including all post-launch content, in one complete collection.

Batman: Arkham Asylum and Batman: Arkham City have been remastered with updated visuals. The collection is completed by Batman: Arkham Knight.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8wgm.jpg', '2018-11-27', '{25,31}', 'IGDB', 99.5665261117019, 112659, 1, 37.99, '[{"id":106346,"rating_category":{"id":6,"rating":"M"}},{"id":94329,"rating_category":{"id":26,"rating":"19+"}},{"id":110973,"rating_category":{"id":12,"rating":"18"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/46949.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/46948.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/398517.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398518.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398519.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/349859.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/349857.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/349858.jpg"]', '{55984,103266,19164,19565,81249,26950,4755,103168,26574,107614}', '{}', 'Warner Bros. Interactive Entertainment', '3', null, null), (854, 'Wizardry: Bane of the Cosmic Forge', 'Ten years ago, Wizardry set the standards in Fantasy Role-Playing (FRP). Now after two million copies have been sold and dozens of awards have been won, Bane of the Cosmic Forge raises and redefines those standards. This new Wizardry , the truest simulation ever of Fantasy Role Playing, will push your computer, your mind, and your sense of adventure to their very limits. Only through the power of the latest computer technology could the full dimensions of this new genre in FRP be possible.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co285x.jpg', '1990-05-21', '{12,31}', 'IGDB', 99.538915764812, 10496, 1, 24.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/8920.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/16599.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/15872.jpg"]', '{106987,96217,115653,81249,19164,55038,55199,103168,26765,27092}', '{}', 'St. GIGA', '0', null, '{211}'), (855, 'The Legend of Zelda: Breath of the Wild - Nintendo Switch 2 Edition', 'Travel across vast fields, through forests, and to mountain peaks as you discover what has become of the kingdom of Hyrule-and step into a world of discovery, exploration, and adventure that''s been upgraded with performance enhancements in The Legend of Zelda: Breath of the Wild - Nintendo Switch 2 Edition! With improved framerates, faster load times, and enhanced resolution and textures, this thrilling open-air adventure has never looked better!

The wilds of Hyrule make for a puzzling game of survival. Climb cliffs to scope out a destination; then cross great distances with the Paraglider or the horses you''ve tamed. You''ll discover items for crafting, beasts to hunt, and plants to forage. Scavenge weapons and armor...or claim them from enemies! From hammers to helmets, items have specific stats, resistances, effects, and levels of durability. Use everything at your disposal to find and conquer more than 100 shrines. Luckily, the in-game Sheikah Slate can project Runes that manipulate objects and enemies in clever ways.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9oy.jpg', '2025-06-05', '{9,31}', 'IGDB', 99.5324223222796, 338072, 1, 79.99, '[{"id":222162,"rating_category":{"id":36,"rating":"M"}},{"id":208029,"rating_category":{"id":10,"rating":"12"}},{"id":208030,"rating_category":{"id":14,"rating":"B"}},{"id":209676,"rating_category":{"id":4,"rating":"E10+"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/260834.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/166161.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1497466.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1804952.jpg"]', '{19164,17548,81249,26574,24426,28070,47823,55984,113360,1877}', '{https://www.youtube.com/watch?v=dmDD7JSfhcE}', 'Nintendo EPD Production Group No. 3', '10', null, '{8988,106}'), (856, 'Deluxe Ski Jump 2', 'Deluxe Ski Jump 2 is the second title in Mediamond''s legendary series of DOS-based ski jumping games.
If your computer does not meet the hardware requirements for DSJ3 you should try this game instead.
Screenshot DSJ2 comes with 32 hills. The available game modes include world cup, team cup and practicing. DSJ2 supports replays and web-based hill records. Up to 16 players can play DSJ2 simultaneously', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9qtx.jpg', '2000-08-31', '{14,32,33}', 'IGDB', 99.4795025888929, 11676, 1, 15.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/96968.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/81018.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/81019.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/81020.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/81021.jpg"]', '{121036,94597,56910,120795,43367,22690,87514,18981,116353,38967}', '{https://www.youtube.com/watch?v=X-pL9knbOj4,https://www.youtube.com/watch?v=suyu3DInwKM}', 'Mediamond', '0', null, '{3156}'), (857, 'American Chopper', 'Be hired into the shop of the hit TV series American Chopper. Here''s your chance to ride the bikes built by the Teutuls. Choose from the POW/MIA Bike, Jet Bike, Black Widow Bike, and others. You''re also sent on missions to create your very own, original themed chopper that rivals those built by Paul Sr. and Paul Jr. Experience first-hand all of the hard work, drama, and thrill of creating one of the most beautiful bikes on the road today.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobouw.jpg', '2004-12-22', '{10}', 'IGDB', 99.4576271186441, 47304, 1, 12.99, '[{"id":72155,"rating_category":{"id":5,"rating":"T"}}]', '[]', '[]', '{118871,113895,66335,119207,77203,58785,51052,48199,41804,25280}', '{https://www.youtube.com/watch?v=wmf8bKGnlZg}', null, '0', null, '{2496}'), (858, 'Golden Axe Warrior', 'World peace is at stake! Death Adder, a wicked giant, has stolen the nine crystals from the kingdom of Firewood and has hidden them in nine labyrinths that he has created. These nine magic crystals protected the people from evil – especially from Death Adder''s grasp. But now that the crystals are lost, the world is defenseless!

Someone must put an end to the fiend''s realm of darkness, death and destruction! Do you have what it takes to bring back peace and happiness? Trek through deep, dark forests and sail across vast, stormy seas. Chop down trees with your Battle Axe and move rocks with your magic spells to find secret caves. When you take on Death Adder''s gruesome monsters, think only of winning – or else you won''t find the nine crystals. And when you do, you''ll find the Golden Axe – the only weapon that can crush Death Adder!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2b8f.jpg', '1991-07-01', '{12}', 'IGDB', 99.4413850372197, 46147, 1, 14.99, '[{"id":167588,"rating_category":{"id":30,"rating":"12"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/355367.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/355369.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/355368.jpg"]', '{54775,106987,57372,96217,28309,80916,19164,81249,55038,113636}', '{}', 'Tec Toy', '0', null, '{956}'), (859, 'Dr. Robotnik''s Ring Racers', 'Dr. Robotnik''s Ring Racers is a kart racing video game originally based on the 3D Sonic the Hedgehog fan-game "Sonic Robo Blast 2", which itself is based on a modified version of Doom Legacy. It is the sequel to Sonic Robo Blast 2 Kart.

Hang up your sneakers, because Dr. Robotnik and his ex-enemies are going go-karting! Use the untapped potential of rings to super-charge your vehicle across more than 200 crazy courses. With over 20 unique items and some of the hottest moves on this side of the Floating Island, this is Racing at the Next Level!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co85ae.jpg', '2024-04-24', '{10}', 'IGDB', 99.4303858366208, 238878, 1, 68.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/999909.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/999910.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/999911.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1243468.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1243469.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1243467.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1311016.jpg"]', '{118871,119207,105011,113360,63138,330461,134690,113895,370215,346826}', '{https://www.youtube.com/watch?v=4lwhzgDbMk4,https://www.youtube.com/watch?v=w1SfxElpijY,https://www.youtube.com/watch?v=KvAJCrdhrrQ}', 'Kart Krew', '12', null, '{6171}'), (860, 'Lizards Must Die', 'The great exploits of the Ancient Rus in the war with the lizards. Immerse yourself in the world of Hyperborea and defeat hordes of Lizards and other unholy who encroached on holy places Ancestors. Choose a blessed hero and go save the world from the green plague.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7888.jpg', '2023-09-27', '{25,32}', 'IGDB', 99.3867372698725, 264773, 1, 64.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/116702.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1134359.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1134360.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1134363.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1134368.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1134369.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1134373.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1134379.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1134355.jpg"]', '{311584,28070,96217,106987,54775,19164,55038,113109,25311,105269}', '{}', 'Agafonoff', '0', '{288903}', null), (861, 'Baldur''s Gate 3: Digital Deluxe Edition', 'The Digital Deluxe Edition upgrade content includes in-game cosmetics, such as a unique custom dice skin to show off to your friends, as well as practical in-game items such as the Mask of the Shapeshifter from Divinity: Original Sin 2.

Listen to the magical music of Borislav Slavov’s Original Soundtrack for Baldur’s Gate 3 or even pick up a pen and play D&D as one of our Origin characters with the handy printable pre-made character sheets. There’s plenty to get stuck into, in and outside of the game.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9bc5.jpg', '2023-08-03', '{12,15,16,24,31}', 'IGDB', 99.3312659885041, 279884, 1, 60.99, '[{"id":162092,"rating_category":{"id":22,"rating":"18"}},{"id":162096,"rating_category":{"id":37,"rating":"MA 15+"}},{"id":162095,"rating_category":{"id":32,"rating":"16"}},{"id":162094,"rating_category":{"id":6,"rating":"M"}},{"id":162091,"rating_category":{"id":12,"rating":"18"}},{"id":162093,"rating_category":{"id":26,"rating":"19+"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/124839.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/153092.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/153093.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/153091.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1432604.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1432603.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1453752.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1453754.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1453756.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1453755.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1453753.jpg"]', '{13196,27092,106987,28182,26845,96217,81249,115653,7615,55038}', '{https://www.youtube.com/watch?v=jNY7AEQ59-8,https://www.youtube.com/watch?v=OcP0WdH7rTs,https://www.youtube.com/watch?v=o5xpbAsly48,https://www.youtube.com/watch?v=tavPnYeFrV4,https://www.youtube.com/watch?v=Ks-KF9iueE0,https://www.youtube.com/watch?v=zTX79cgruXE,https://www.youtube.com/watch?v=XuCfkgaaa08}', 'Larian Studios', '0', null, null), (862, 'Grand Theft Auto V: Special Edition', 'The Grand Theft Auto V Special Edition includes:
- Full retail copy of Grand Theft Auto V
- Collectible SteelBook with exclusive artwork featuring custom colour and metallic treatments for the Michael, Trevor and Franklin design
- Blueprint map (21.5” x 26.75”) displaying a blueprint view of Los Santos and Blaine County
- Special ability boost that allows Michael, Franklin and Trevor’s special ability bars to regenerate 25% faster
- Stunt Plane Trials offering additional single-player aerial challenges across Los Santos and Blaine County
- Bonus outfits, tattoos and special shop deals for Michael, Franklin and Trevor
- Additional weapons available for free at Ammu-Nation in single-player: Pistol .50, Bullpup Shotgun and Hammer', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nbc.jpg', '2013-09-17', '{5,10,14}', 'IGDB', 99.3100933273888, 45131, 1, 22.99, '[{"id":211384,"rating_category":{"id":12,"rating":"18"}},{"id":211385,"rating_category":{"id":22,"rating":"18"}},{"id":90110,"rating_category":{"id":6,"rating":"M"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/393460.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/393461.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/393462.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/344198.jpg"]', '{19164,105011,118871,119161,95340,37419,119177,106805,81249,87622}', '{}', 'Take-Two Interactive', '0', null, null), (863, 'Undertale Yellow', 'Welcome to Undertale Yellow. In this fan made prequel to the RPG Undertale, you control a human who falls underground into the world of monsters... but will you make it out alive?

Grab your cowboy hat and your gun and take the place of Undertale’s Yellow soul in their journey through the Underground on an original adventure.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2el1.jpg', '2023-12-09', '{12,16,31,32}', 'IGDB', 99.2211161128955, 136482, 2, 64.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/395024.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/395025.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/395026.jpg"]', '{106987,96217,115653,19164,94772,24426,47823,28182,19404,28309}', '{https://www.youtube.com/watch?v=Vru1B9snXoo,https://www.youtube.com/watch?v=POm2vYOz-9A,https://www.youtube.com/watch?v=OLcWNk-4HJw,https://www.youtube.com/watch?v=pr4OTPFtLrA}', 'Team Undertale Yellow', '0', null, null), (864, 'Angband', 'Angband is an open-source roguelike, the goal of which is to survive 100 floor levels of the fortress Angband in order to defeat Morgoth.

The player begins in a town where they can buy equipment before beginning the descent. Once in the maze-like fortress, the player encounters traps, monsters, equipment, and hidden doors. With the help of found objects and enchantments, the player''s attack and defense power increases, and can even neutralize specific attacks.

Angband gameplay emphasises combat and careful resource management. The player has finite health points, and death is final. Although Angband records the player''s progress to a save file, it does not allow one to resume a saved game in which the player character has already died. If the player overcomes Morgoth on the 100th floor, the game continues, and the player may continue descending to further floors. The levels are procedurally generated, allowing for a unique game in every play.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ute.jpg', null, '{12,25}', 'IGDB', 99.0718232676503, 50261, 2, 79.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/243128.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/243130.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/243129.jpg"]', '{54775,103168,115308,103303,113109,19404,27209,106987,96217,115653}', '{}', null, '12', null, null), (865, 'Terraria: Calamity Mod', 'The Calamity Mod is a large content mod for Terraria which adds many hours of endgame content and dozens of enemies and bosses dispersed throughout the vanilla game''s progression. The Calamity Mod also features several harder difficulty modes, five new biomes and new structures, a new class, more than thirty new songs, over fifty recipes for previously uncraftable vanilla items and other assorted changes to vanilla gameplay.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobryq.jpg', '2016-06-01', '{8,12,13,15,31,32}', 'IGDB', 99.0430413447168, 141229, 0, 53.99, '[{"id":31208,"rating_category":{"id":10,"rating":"12"}},{"id":31207,"rating_category":{"id":5,"rating":"T"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1801328.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1801329.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1801330.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1801331.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1801332.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1801333.jpg"]', '{26574,25311,109339,35994,17548,17379,25300,44076,10776,26145}', '{https://www.youtube.com/watch?v=R9wYNI5y7bw,https://www.youtube.com/watch?v=oQ74IZaj5Q8}', null, '5', null, null), (866, 'Rooftop Rascal: The Midnight Cat', 'In "Rooftop Rascal: The Midnight Cat," you control a clever cat navigating city buildings'' fire escape stairs to the rooftop.
The gameplay centres on jumps, and quick thinking.
Your goal is to climb as high as you can and reach the rooftop.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8tkn.jpg', '2024-08-12', '{8,32}', 'IGDB', 98.9134125636672, 315893, 0, 60.99, '[{"id":185256,"rating_category":{"id":3,"rating":"E"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/144984.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/262137.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1391000.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1391001.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1391002.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1391003.jpg"]', '{113895,20342,55173,24426,28070,89597,391211,386286,386032,385440}', '{}', 'chroda.eu', '0', null, '{12821}'), (867, 'Micro Machines', 'Sega Genesis port of Micro Machines', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6psu.jpg', '1993-07-01', '{10}', 'IGDB', 98.8659769996668, 250469, 0, 28.99, '[]', '[]', '[]', '{109292,55192,104983,44178,80382,27553,107227,102023,27378,396794}', '{}', 'Codemasters', '11', null, '{1182}'), (868, 'Pixadom', 'Pixadom is a cozy 2D top-down social MMORPG with a charming pixel art style, playable directly in your browser on any modern device. Set in a vibrant world designed for social interaction, Pixadom blends the nostalgia of classic games with a fresh, community-driven experience. Players can enjoy a variety of activities, explore a richly detailed world, and participate in regular events. With a focus on community and creativity, Pixadom offers a unique, engaging multiplayer adventure that evolves through weekly updates and player-driven content.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co902g.jpg', '2024-08-20', '{8,12,31,32}', 'IGDB', 98.824280123789, 317582, 0, 72.99, '[]', '[]', '[]', '{106987,96217,24426,19404,19150,29348,68582,28309,28070,47823}', '{https://www.youtube.com/watch?v=3cKON_5vTks}', null, '0', null, null), (869, 'Anstoss 3', '2000 wurde mit Anstoss 3 die zweite Fortsetzung veröffentlicht. Innerhalb eines Jahres verkaufte es sich mehr als 200.000 Mal. Von den Spielemagazinen wurde es mit guten Wertungen bedacht (z. B. PC Player 87 %, Gamestar 88 %, PC Games 86 %).
Jedoch war es zu Beginn geradezu gefüllt mit Bugs, was von der Spielergemeinde kritisiert wurde. Dennoch wurde es von den Anstoss-Fans mit Begeisterung aufgenommen, da es die wichtigsten Elemente von Anstoss 2 Gold enthielt und diese noch weiter vertiefen konnte.
Als besonders gelungen gilt die 3D-Spieldarstellung. Der Spieler konnte sich ein komplettes Spiel seines Teams reduziert auf neun Minuten ansehen. Auch der Szenenmodus galt als revolutionär, da die Szenen nicht, wie in den Vorgängerteilen, vorberechnet wurden. Kommentiert wurden die Spielszenen durch den bekannten Fußballkommentator Günther Koch.
Auch neu war die Umsetzung des Vereinsgeländes. Von Apfelbäumen über Konditionsparcours und Doping-Labor bis hin zu Wolkenkratzern konnte der Spieler sein Vereinsgelände mit Gebäuden, Gegenständen und Lebewesen mit und ohne Nutzen erweitern.
Mit der Veröffentlichung des finalen Patches auf Version 1.40 wurde es nahezu bugfrei und konnte die Anstoss-Spieler überzeugen. Insgesamt wurden bis heute über eine Million Exemplare von Anstoss 3 verkauft und machen es damit zu einem der erfolgreichsten PC-Spiele Deutschlands. Trotz seines Alters wird Anstoss 3 durch die große Spieltiefe zusammen mit einem gelungenen Text- und 3D-Modus als bester Teil der Anstoss-Reihe angesehen. Dass Anstoss 3 auch heute noch sehr beliebt ist, hängt auch mit dem Multiplayermodus zusammen. So wird es bis zu 4 Spielern ermöglicht, im Netzwerk gegeneinander anzutreten.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ky3.jpg', '2000-06-01', '{13,14}', 'IGDB', 98.7521301458658, 11226, 2, 17.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/40881.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/515729.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/515731.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/515732.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/515733.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/515730.jpg"]', '{29173,117717,55888,116353,38967,118871,115869,112846,113105,41621}', '{https://www.youtube.com/watch?v=cTZ7RNaWKbk}', 'Ascaron Entertainment', '0', null, '{1499}'), (870, 'Adastra', 'After being kidnapped by a wolf-like alien, a man from Earth finds himself caught up in the messy political affairs of a race that has recently lost its emperor.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ata.jpg', '2020-06-12', '{34}', 'IGDB', 98.7287632172983, 135341, 1, 55.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/163101.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/414409.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/414410.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/414411.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/414413.jpg"]', '{41895,28465,9648,67166,22472,12328,75900,182275,43130,22425}', '{}', 'Echo Project', '0', null, '{6405}'), (871, 'San Andreas Multiplayer', 'SA-MP is a free Massively Multiplayer Online game mod for the PC version of Rockstar Games Grand Theft Auto: San Andreas', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9puv.jpg', '2006-05-09', '{5,10}', 'IGDB', 98.7207313276821, 199038, 4, 27.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/781736.jpg"]', '{109292,58095,44178,80382,95340,294712,250038,177206,174550,47561}', '{https://www.youtube.com/watch?v=-PWXXvHe35M}', null, '5', null, null), (872, 'Rooftop Rascal: The Spooky Cat', 'In "Rooftop Rascal: The Spooky Cat," take control of a nimble cat scaling fire escapes and rooftops in a Halloween-themed adventure. Test your quick thinking and jumping skills as you climb higher and higher to reach the rooftop.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobucm.jpg', '2024-10-20', null, 'IGDB', 98.6776859504132, 320373, 0, 61.99, '[{"id":191569,"rating_category":{"id":3,"rating":"E"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/147670.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/262136.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1411814.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1411815.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1411816.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1411817.jpg"]', null, '{}', 'chroda.eu', '0', null, '{12821}'), (873, 'Gwent: Iron Judgment', 'The North is on the rise and Radovid is back to bring justice to his enemies — the kind of justice that is being served by fire and iron. Stand by his side or defy royal authority — whichever you choose, get ready for some of the fiercest battles in GWENT’s history. Relive the Battle of Brenna, learn the secrets of the Salamandra, or join Gascon’s company of noble criminals — there is plenty of opportunities to get into a fight in GWENT: Iron Judgment.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1r5n.jpg', '2019-10-02', '{15,35}', 'IGDB', 98.6290549226521, 122661, 0, 49.99, '[{"id":25968,"rating_category":{"id":5,"rating":"T"}},{"id":25969,"rating_category":{"id":11,"rating":"16"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/361511.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/361507.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/361509.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/361513.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/361510.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/361512.jpg"]', '{19404,32510,56967,119156,113201,13196,7615,119188,111187,77498}', '{https://www.youtube.com/watch?v=4hN8TC9u61Q}', 'CD Projekt', '2', null, '{62}'), (874, 'Chrono Trigger', 'An enhanced port of Chrono Trigger that adds anime cutscenes and an exclusive Extras Mode. It is also known for having significantly longer load times in comparison to the original SNES version.

Extras Mode is an option in the main menu that let players view cutscenes and artwork, listen to music, and view information about techs, enemies, bosses, endings, and item locations.

It was first released for PlayStation in Japan before it came to North America as part of the Final Fantasy Chronicles compilation.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7mnm.jpg', '1999-11-02', '{12}', 'IGDB', 98.599447900661, 263446, 1, 10.99, '[{"id":163482,"rating_category":{"id":13,"rating":"A"}},{"id":163481,"rating_category":{"id":5,"rating":"T"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/266024.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266020.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266022.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266023.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266021.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1218930.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1218931.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1816102.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1816103.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1816104.jpg"]', '{55038,106987,54775,96217,1447,22387,36198,113109,19164,19150}', '{https://www.youtube.com/watch?v=m1Sb9CZEz9A,https://www.youtube.com/watch?v=ib4KbKEOTZ0}', 'Square Enix', '10', null, '{345}'), (875, 'Goblin Sword', 'Goblin Sword is a retro-inspired action platformer with light rpg elements.

An army of monsters led by an evil wizard have invaded your hometown. Slay as many monsters as you can, collect loot, avoid dangerous traps and defeat menacing bosses, before facing the evil wizard himself.

Reviews:
“It''s such a crazy value and has such good production quality it kind of speaks for itself.” 5/5 TouchArcade
"Fun visuals, good music, engaging level design, and lots of content make Goblin Sword an excellent little game." Editor''s Choice -148 Apps
“A deeply compelling and staggeringly impressive tribute to retro games.” 10/10 ArcadeLife

Features:
-89 levels
-13 bosses
-30 weapons with unique special attacks
-30 relics that grant you abilities
-14 costumes
-8 guardians that follow you around and assist you
-5 secret very hard levels
-Decorate your home with souvenirs
-Customizable touch controls
-Universal app. Works on iPad, iPhone and iPod touch.
-iCloud and MFi support
-Game Center achievements and leaderboards
-Premium game. No IAP or ads ever.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zdd.jpg', '2014-09-11', '{8,12,31}', 'IGDB', 98.5155743564026, 88973, 1, 18.99, '[{"id":55213,"rating_category":{"id":9,"rating":"7"}},{"id":39721,"rating_category":{"id":3,"rating":"E"}},{"id":94421,"rating_category":{"id":23,"rating":"ALL"}},{"id":98925,"rating_category":{"id":13,"rating":"A"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/14689.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/208581.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/208574.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/208580.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/208578.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/208579.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/208576.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/208577.jpg"]', '{106987,28309,24426,89597,96217,115280,81249,80916,30245,103168}', '{https://www.youtube.com/watch?v=53L3_duBZLk}', 'Gelato Games', '0', null, null), (876, 'Pokémon Infinite Fusion', 'Pokémon Infinite Fusion is a fangame RPG based on the Pokémon fusion generator trend, featuring sprite art from many different artists.

With thousands of fusions available, even Professor Oak doesn''t expect you to "catch ''em all"!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7k5u.jpg', '2015-04-22', '{12,31,32}', 'IGDB', 98.4708050193513, 143761, 1, 7.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1117930.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1117931.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1117932.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1117933.jpg"]', '{106987,96217,24426,47823,28309,80916,19164,17548,81249,55038}', '{}', null, '0', null, null), (877, 'Kingdom Hearts II Final Mix+', 'Kingdom Hearts II Final Mix+ is a Japan-exclusive 2007 combo pack of Kingdom Hearts II Final Mix, the "Final Mix" version of Kingdom Hearts II and Kingdom Hearts Re:Chain of Memories, a remake of Kingdom Hearts: Chain of Memories. Kingdom Hearts II Final Mix features new cutscenes, abilities, weapons, enemies, areas, and a new form, while Kingdom Hearts Re:Chain of Memories features new cards, cutscenes and mini-games.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co30ss.jpg', '2007-03-29', '{12,31}', 'IGDB', 98.4365689102255, 43651, 1, 20.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/84086.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/391803.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/391802.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/391804.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/108595.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/108594.jpg"]', '{106987,81249,96217,103303,103168,101608,28010,55038,55199,19164}', '{https://www.youtube.com/watch?v=Vkhc9NDHksc}', 'Buena Vista Games', '3', null, null), (878, 'ITGmania', 'ITGmania is a cross-platform rhythm game and engine. Similar to Dance Dance Revolution, it is often played with dance mats or pads. Although originally created to simulate the now defunct game, In The Groove, it has since grown to be a completely community driven effort providing regular new content and updates.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8wsz.jpg', '2022-06-12', '{7,33}', 'IGDB', 98.4, 297623, 1, 50.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1404488.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1404489.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1404490.jpg"]', '{87150,63933,18981,60812,46801,108759,86880,90965,119207,368758}', '{}', null, '12', null, null), (879, 'Gwent: Crimson Curse', 'Along with a multitude of new tools for waging war, Crimson Curse introduces over 100 cards across all of GWENT’s playable factions. Players will be able to afflict the enemy with Poison and Bleeding, use Shield and Vitality to defend against incoming damage, as well as attempt to turn the tide of battle using the Deathblow and Berserk gameplay mechanics.

As always, every card comes in both a standard version and a premium animated variant — one of the hallmark features of GWENT’s presentation.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1yw9.jpg', '2019-03-28', '{15,35}', 'IGDB', 98.3916197468336, 115776, 1, 34.99, '[{"id":24912,"rating_category":{"id":5,"rating":"T"}},{"id":24913,"rating_category":{"id":10,"rating":"12"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/6689.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/361559.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/361556.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/361557.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/361558.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/361561.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/361560.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/361562.jpg"]', '{19404,32510,56967,119156,113201,13196,7615,119188,111187,77498}', '{https://www.youtube.com/watch?v=QqmLAEEOrSQ,https://www.youtube.com/watch?v=u_uNNlXNXmw}', 'CD Projekt RED', '2', null, '{62}'), (880, 'Alone in the Dark: The New Nightmare', 'The Dreamcast, PC and PlayStation 2 ports of Alone in the Dark: The New Nightmare, which feature major graphic improvements and the addition of lip synchronization for the polygon models during cutscenes.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ldv.jpg', '2001-06-22', '{9,31}', 'IGDB', 98.3689019095739, 266501, 1, 29.99, '[{"id":172145,"rating_category":{"id":6,"rating":"M"}},{"id":172148,"rating_category":{"id":32,"rating":"16"}},{"id":172147,"rating_category":{"id":20,"rating":"12"}},{"id":172146,"rating_category":{"id":10,"rating":"12"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/135049.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1295380.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1295381.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1295382.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1295383.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1295378.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1295379.jpg"]', '{25646,115304,11668,18225,18011,111130,56033,107614,26658,55984}', '{https://www.youtube.com/watch?v=mb6XExJq1p4}', 'Darkworks', '11', null, '{364}'), (881, 'The Binding of Isaac: Repentance', 'The Binding of Isaac: Repentance is the ultimate edition of the genre-defining roguelike, with so many additions and improvements that it feels like a brand new game. Experience Isaac''s adventures with new twists, terrifying turns and over 500 hours of new gameplay!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8kxf.jpg', '2021-11-03', '{5,32}', 'IGDB', 98.364844149208, 310643, 0, 60.99, '[{"id":183815,"rating_category":{"id":6,"rating":"M"}},{"id":182082,"rating_category":{"id":11,"rating":"16"}},{"id":183559,"rating_category":{"id":26,"rating":"19+"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/144062.jpg"]', '[]', '{32902,43367,113895,105269,58095,107318,25633,102868,106326,119493}', '{}', 'Edmund McMillen', '1', null, '{12491}'), (882, 'Ena: Dream BBQ', 'Experience surreal environments and inexplicable characters as ENA in a new wild world.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co62ei.jpg', '2025-03-27', '{31,32}', 'IGDB', 98.136560218048, 172496, 1, 91.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/100309.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/228805.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/970501.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/970502.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/970503.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/970504.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/970505.jpg"]', '{23733,8968,15537,103329,119298,16992,109129,26226,9174,20329}', '{https://www.youtube.com/watch?v=kQebudKEHT0,https://www.youtube.com/watch?v=yzNcZdCYat0,https://www.youtube.com/watch?v=qLurAhsqXWc}', 'Joel G', '0', null, null), (883, 'Chicken Derby', 'Chickens are running on the Polygon Blockchain!
Race to win money on your way to podium glory with your NFT Chicken collection.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coblnv.jpg', '2021-07-16', '{10}', 'IGDB', 98.0952380952381, 391882, 1, 76.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/252788.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1785063.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1785065.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1785075.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1785066.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1785076.jpg"]', '{247304,109292,44178,80382,27553,27378,55192,104983,55217,40470}', '{https://www.youtube.com/watch?v=55a0C_8BXHQ,https://www.youtube.com/watch?v=cB48ptnEmHM}', null, '0', null, null), (884, 'OneShot: World Machine Edition', 'The World Knows You Exist.

Experience an adventure game with puzzles that go beyond its own window and establish a unique bond with the main character.

In OneShot: World Machine Edition, you discover a strange computer operating system with a self-contained world installed. Explore this world to unravel its mysteries and help guide a child on their mission to restore the long-dead sun.

You hear that saving the world may no longer be possible… But it’s worth a shot, you think. Now with collectible content and features exclusive to the World Machine Edition!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ldh.jpg', '2022-09-22', '{9,12,31,32}', 'IGDB', 98.0912277726544, 200905, 1, 66.99, '[{"id":93219,"rating_category":{"id":3,"rating":"E"}},{"id":93778,"rating_category":{"id":23,"rating":"ALL"}},{"id":90690,"rating_category":{"id":13,"rating":"A"}},{"id":88052,"rating_category":{"id":8,"rating":"3"}},{"id":110541,"rating_category":{"id":34,"rating":"G"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/76199.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/792070.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/792072.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/792074.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/792075.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/792077.jpg"]', '{18182,23733,24426,26226,36198,236,12517,1877,111253,28070}', '{https://www.youtube.com/watch?v=RHqHxAPylCg,https://www.youtube.com/watch?v=eqY5b1iDLi0}', 'Komodo', '10', null, null), (885, 'Batman: Arkham Knight - Premium Edition', 'Batman: Arkham Knight is an action-adventure game developed by Rocksteady Studios, released in 2015. It is the final installment in the Arkham series. Players control Batman as he faces Scarecrow, who unites Gotham''s criminals to destroy the Dark Knight. The mysterious Arkham Knight, a new adversary, aids Scarecrow in his plan.

The game features open-world exploration, stealth, combat, and puzzle-solving. A key addition is the Batmobile, used for traversal and combat. The story explores Batman’s psychological struggles and the collapse of his alliances as Gotham spirals into chaos.

It includes the main game and the season pass.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fr0.jpg', '2015-06-23', '{25,31}', 'IGDB', 98.0411508673547, 52440, 1, 20.99, '[{"id":29777,"rating_category":{"id":6,"rating":"M"}},{"id":108531,"rating_category":{"id":36,"rating":"M"}},{"id":94011,"rating_category":{"id":26,"rating":"19+"}},{"id":110653,"rating_category":{"id":12,"rating":"18"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/46779.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/46777.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/397951.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/397952.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/349983.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/349984.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/349985.jpg"]', '{55984,103266,19164,81249,103168,26574,107614,103054,19565,115283}', '{https://www.youtube.com/watch?v=wsf78BS9VE0,https://www.youtube.com/watch?v=VpXUIh7rlWI}', 'Warner Bros. Interactive Entertainment', '3', null, '{68}'), (886, 'Orion Sandbox', 'This is a 2D crafting survival sandbox game. You will be able to explore a huge 2D side-view world, building houses, crafting tools, weapons and armour from the resources you collect. There is a day/night cycle and each night many dangerous monsters can be found and defeated.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobtka.jpg', '2016-05-31', '{12,31,32}', 'IGDB', 98, 395783, 1, 34.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/260816.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/260817.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/260814.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/260815.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/261254.jpg"]', '[]', '{29348,106987,28309,113402,47823,96217,26574,80916,30245,105269}', '{https://www.youtube.com/watch?v=gVQYGPesfi8}', 'Y8.com', '0', null, null), (887, 'The Talos Principle II: Road to Elysium', 'Road to Elysium is a three-part coda that allows you to dive deeper into the world of The Talos Principle 2, reunite with beloved characters, and put your puzzle-solving skills to the test through a series of thought-provoking new stories.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co970v.jpg', '2024-06-14', '{9,31,32}', 'IGDB', 98, 305040, 1, 63.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/204455.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1337522.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1337520.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1337518.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1337517.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1337521.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1337516.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1337519.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1337523.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1337525.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1337515.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1337524.jpg"]', '{28070,25646,105269,25311,107318,20342,111130,55173,24426,55190}', '{https://www.youtube.com/watch?v=M84Z1fS8hPc,https://www.youtube.com/watch?v=o2mlbKU-fFE}', 'Croteam', '2', null, '{9600}'), (888, 'Captain of Industry', 'Factory construction and management simulator. Alone with your loyal crew, expand a small colony of survivors into an industrial empire! From an abandoned island to vast factories, research labs, and space program. Build, mine, farm, shape terrain, explore and take care of your settlement!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co31hc.jpg', '2022-05-31', '{13,15,32}', 'IGDB', 98, 150100, 1, 54.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/32673.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/473255.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/473256.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/473257.jpg"]', '{26574,44242,9243,51577,109339,106279,34823,9789,26145,19542}', '{https://www.youtube.com/watch?v=U0d7z2sBr-4}', 'MaFi Games', '0', null, null), (889, 'Dragon Age: Origins Collector''s Edition', 'Dragon Age: Origins Collector''s Edition contains :

- Tin case.
- Bonus DVD including:
- A making of documentary
- Soundtrack
- Trailers
- Wallpaper
- Concept art video
- Strategy tips
- Cloth map
- 3 pieces of exclusive in-game content:
- Bergen’s Honor: A massive helmet made out of dragonbone (+2 to armor, +25 physical resistance, +6 to attack).
- Grimoire of the Frozen Wates: A special book that adds +3 to all attributes when read.
- Final Reason: A magical staff of immense power (adds to damage, spell power, and fire damage).
- "The Stone Prisoner" unlockable bonus quest and unlockable character, Shale.
- Exclusive in-game item for use in the upcoming title Mass Effect 2.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95y5.jpg', '2009-12-03', '{12}', 'IGDB', 98, 21765, 1, 12.99, '[{"id":89184,"rating_category":{"id":12,"rating":"18"}},{"id":189291,"rating_category":{"id":6,"rating":"M"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/29497.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1046889.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1046890.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1046891.jpg"]', '{113636,54775,106987,81249,96217,23651,49414,103168,101608,28010}', '{}', 'Electronic Arts', '0', null, null), (890, 'The Witcher 3: Wild Hunt - Game of the Year Edition', 'The Witcher 3: Wild Hunt – Game of the Year Edition is a complete version of the game released in August 2016 for PC, PlayStation 4, and Xbox One. It includes the base game along with all post-launch content, including the two major expansions, Hearts of Stone and Blood and Wine, and all free DLCs.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wz4.jpg', '2016-08-29', '{12,31}', 'IGDB', 97.9627268838697, 22439, 1, 48.99, '[{"id":13900,"rating_category":{"id":12,"rating":"18"}},{"id":69670,"rating_category":{"id":17,"rating":"Z"}},{"id":123159,"rating_category":{"id":22,"rating":"18"}},{"id":110975,"rating_category":{"id":38,"rating":"R 18+"}},{"id":106965,"rating_category":{"id":26,"rating":"19+"}},{"id":125907,"rating_category":{"id":32,"rating":"16"}},{"id":188126,"rating_category":{"id":6,"rating":"M"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/47101.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/47102.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/117438.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/117439.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/117440.jpg"]', '{19164,81249,55199,34155,106987,96217,115653,105049,17548,55038}', '{https://www.youtube.com/watch?v=5wmNeg5WVck,https://www.youtube.com/watch?v=YmLeUJgzsXY,https://www.youtube.com/watch?v=qy8jmm9kY4A}', 'CD Projekt RED', '3', null, null), (891, 'Epiko Regal', 'Epiko Regal is an immersive mobile strategy game that seamlessly blends collectible card gameplay with tower defense battles. Players build and upgrade their decks, which include a wide range of troops, spells, weapons, and buildings, all deployed strategically onto the battlefield. The objective is to defend your towers and engage in dynamic battles against other players to emerge victorious.

As part of the Web3 Gaming Ecosystem, called EPIKO, Epiko Regal offers unique benefits to holders of Epiko NFTs. Players who own these NFTs can claim exclusive in-game rewards, enhancing their gameplay experience. These rewards include rare items, special abilities, and access to exclusive content, helping NFT holders gain a competitive edge in the game.

In addition, Epiko Regal features Mystery Stones—special items that allow players to redeem valuable in-game content like Gems, Gold, higher-level cards, Digital Toys, and chapters from the Kathika Comics. These Mystery Stones can only be unlocked with a redeem code, which players receive when they purchase Epiko NFTs or win them during special events.

Explore the depths of Epiko''s universe and unlock exclusive rewards with your Epiko NFTs.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8wq0.jpg', '2024-08-15', '{11,15,24,35}', 'IGDB', 97.821058428879, 318575, 1, 72.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1402484.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1402485.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1402486.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1402487.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1402483.jpg"]', '{15707,119156,13196,27092,107218,113201,5589,40477,58075,6985}', '{https://www.youtube.com/watch?v=-iRfzuX8Xsc}', 'Wharf Street Studios', '0', null, null), (892, 'Umineko no Naku Koro ni Chiru', 'Umineko no Naku Koro ni Chiru is the sequel to Umineko no Naku Koro Ni. It is also referred to as When They Cry 4 in the overall When They Cry franchise.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4szy.jpg', '2011-09-01', '{31,34}', 'IGDB', 97.7422616836606, 51267, 1, 23.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1727231.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1728291.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1728292.jpg"]', '{15830,8968,67173,55984,114150,79848,67228,55935,79846,17906}', '{}', '07th Expansion', '3', null, '{1622}'), (893, 'Streets of Rage Remake', 'Streets of Rage Remake is a fangame reboot on the trilogy Streets of Rage.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2srh.jpg', '2011-04-03', '{25,32}', 'IGDB', 97.5701213851357, 72327, 1, 26.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/127037.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/127038.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/127039.jpg"]', '{14704,25311,105269,17130,55190,56033,19301,21564,28070,55173}', '{https://www.youtube.com/watch?v=V9r5IYrtyEc}', 'Bombergames', '0', null, null), (894, 'Maestro', 'Step into a gorgeous opera house with Maestro, the VR orchestra conducting rhythm game that''s the essence of elegance, control, and high-society french sophistication.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8elu.jpg', '2024-10-17', '{7,13,32}', 'IGDB', 97.5, 306924, 1, 75.99, '[{"id":212037,"rating_category":{"id":5,"rating":"T"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/140325.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/185633.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/185634.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1347948.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1347947.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1347949.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1347950.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1347951.jpg"]', '{18623,23345,79134,55590,36553,102163,31480,35371,27792,78550}', '{https://www.youtube.com/watch?v=s6U9dKBchGI,https://www.youtube.com/watch?v=A-r3YO4DoWU}', 'Double Jack', '0', '{371280,344161}', null), (895, 'Love Eternal', 'Wander a castle built of bitter memories in LOVE ETERNAL, a psychological horror platformer with devious trials and an unsettling, experimental narrative. Find a way out - or live in Shelter forever more.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8dts.jpg', '2026-02-19', '{8,31,32}', 'IGDB', 97.5, 305358, 1, 83.99, '[{"id":229622,"rating_category":{"id":10,"rating":"12"}},{"id":230123,"rating_category":{"id":5,"rating":"T"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/140065.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1339264.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1344653.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1344656.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1344651.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1339267.jpg"]', '{111130,56033,55282,13189,25646,25222,27266,18011,2034