9,"rating_category":{"id":10,"rating":"12"}},{"id":97169,"rating_category":{"id":25,"rating":"15+"}},{"id":111810,"rating_category":{"id":34,"rating":"G"}},{"id":125200,"rating_category":{"id":28,"rating":"L"}},{"id":160081,"rating_category":{"id":13,"rating":"A"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/53220.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/646636.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/646638.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/646639.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/646637.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/646640.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/646641.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/646642.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/646643.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/646644.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/646645.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/646646.jpg"]', '{25311,11737,37419,26574,28070,25646,80916,26223,55984,17548}', '{https://www.youtube.com/watch?v=yniQwQlyUl8}', 'Mobius Digital', '3', null, '{6980}'), (1001, 'Metal Gear Solid 3: Snake Eater - HD Edition', 'A remastered version of Metal Gear Solid 3: Snake Eater, featuring updated controls and graphical improvements.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co98hv.jpg', '2011-11-08', '{5,24,31}', 'IGDB', 94.7336042767572, 99821, 1, 14.99, '[{"id":144152,"rating_category":{"id":6,"rating":"M"}},{"id":151152,"rating_category":{"id":16,"rating":"D"}},{"id":143611,"rating_category":{"id":12,"rating":"18"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/110668.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/338723.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/338722.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/338721.jpg"]', '{55038,105269,107318,103301,118218,19564,103292,68287,90099,19164}', '{https://www.youtube.com/watch?v=bDPwFx7ogxI,https://www.youtube.com/watch?v=DqJFsqr4zsE,https://www.youtube.com/watch?v=RwImlDapheQ}', 'Bluepoint Games', '9', null, '{2128}'), (1002, 'The Elder Scrolls IV: Oblivion - Game of the Year Edition Deluxe', 'The Elder Scrolls IV: Oblivion Game of the Year Edition presents one of the best RPGs of all time like never before. Step inside the most richly detailed and vibrant game-world ever created. With a powerful combination of freeform gameplay and unprecedented graphics, you can unravel the main quest at your own pace or explore the vast world and find your own challenges.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ymf.jpg', '2009-06-16', '{12,31}', 'IGDB', 94.7137574600736, 27844, 1, 22.99, '[{"id":123102,"rating_category":{"id":20,"rating":"12"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/38368.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/38365.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/38364.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/38366.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/38367.jpg"]', '{19164,9243,17548,81249,14394,26574,113360,34155,47823,96217}', '{https://www.youtube.com/watch?v=obAWr_FGE3k}', 'Bethesda Game Studios', '3', null, null), (1003, 'My Grandfather''s Farm', '"Your grandfather left you his old farm. With only a few coins and tools and with the help of your grandfather you have to go to the old farm 
give new shine again! 
 
Can you live from what the land has to offer you? 
 
Give the old farm a new lease of life - expand your farm. Buy new fields, stables, equipment and animals. 
Farm your animals, farm your fields. 
Sell ​​your goods to dealers or directly to the inhabitants of Lodo Paws to build your yard! Make friends with the inhabitants of Lodo Paws. 
Harvest various types of crops, potatoes, carrots, wheat, corn, sunflowers. Take care of your animals (cows, sheep, chickens, horses). 
Watch for the seasons to catch up with your harvest in time. 
Cut down trees and transport the wood or your goods by horse and cart. 
 
Adapt your farmer! Buy new clothes or change your outfit! 
 
Explore Lodo Paws, explore the Thunder Mine and find valuable treasures. 
Complete tasks and quest''s."', 'https://images.igdb.com/igdb/image/upload/t_cover_big/s9v8ggxiaqwtp3n0koas.jpg', '2018-08-30', '{12,13,15,31,32}', 'IGDB', 94.6722873890479, 98753, 1, 55.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/238441.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/238444.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/238440.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/238442.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/238443.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/238447.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/238448.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/238446.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/238449.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/238451.jpg"]', '{109339,25311,35994,29348,29173,26574,26145,103232,79134,113402}', '{}', 'CHG', '0', null, null), (1004, 'Final Fantasy III', 'Final Fantasy III is the sixth main installment in the Final Fantasy series, developed and published by Square. It was the final title in the series to feature two-dimensional graphics, and the first story that did not revolve around crystals.

The game gives players up to fourteen playable characters, the largest cast in the series, and features the Active Time Battle pseudo-turn based menu command system. A party can consist of up to four characters, though some events require the player to assemble three different parties of up to four and switch between them.

Each character has a unique command ability, such as Terra''s Trance, Locke''s Steal, Edgar''s Tools or Sabin''s Blitz, and can also learn Magic spells from earning AP from battles with magicite equipped. Each character''s rare Desperation Attack will randomly activate after using the Attack command when at critical health.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaq5k.jpg', '1994-04-02', '{12,31}', 'IGDB', 94.6308033686418, 426, 1, 20.99, '[{"id":222948,"rating_category":{"id":4,"rating":"E10+"}},{"id":222949,"rating_category":{"id":9,"rating":"7"}},{"id":222950,"rating_category":{"id":29,"rating":"10"}},{"id":97558,"rating_category":{"id":14,"rating":"B"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/171653.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/217785.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/217786.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/437009.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/437010.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/437011.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/437012.jpg"]', '{421,425,398,428,832,384,533,538,1804,20}', '{https://www.youtube.com/watch?v=oWD1m3Q7AV4,https://www.youtube.com/watch?v=pEgrzE6oGKQ,https://www.youtube.com/watch?v=72DmCaczYMc,https://www.youtube.com/watch?v=d15qmRzn2Pc,https://www.youtube.com/watch?v=gt5l5cG2E08}', 'Square', '0', null, '{39}'), (1005, 'Sengoku Rance', 'Sengoku Rance (also known as "Rance 7") is the tenth release of the Rance series launched by Alicesoft. The story takes place during the 4th sengoku (warring states) era of JAPAN, an area of the Rance World which parodies medieval real-world Japan.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7k0m.jpg', '2006-12-15', '{12,15,16,31,34}', 'IGDB', 94.5826695200275, 37138, 1, 21.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/96118.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/44375.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/44376.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/379883.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/379882.jpg"]', '{22422,19785,16309,41895,22423,26845,26022,22425,59173,22421}', '{https://www.youtube.com/watch?v=-TXVGnfF2Yk}', 'Alicesoft', '0', null, '{2786}'), (1006, 'Paper Mario: The Thousand-Year Door', 'A remake of the second game in the Paper Mario series, originally released for the Nintendo GameCube.

Turn the page and join Mario and friends in an RPG adventure to discover the legendary treasure behind the ancient Thousand-Year Door. Will Mario complete his papery quest, or will he crumple under the pressure?', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9xy.jpg', '2024-05-23', '{12,31}', 'IGDB', 94.5781231373159, 266690, 1, 65.99, '[{"id":205014,"rating_category":{"id":23,"rating":"ALL"}},{"id":176923,"rating_category":{"id":9,"rating":"7"}},{"id":166834,"rating_category":{"id":28,"rating":"L"}},{"id":205013,"rating_category":{"id":18,"rating":"0"}},{"id":176924,"rating_category":{"id":14,"rating":"B"}},{"id":176925,"rating_category":{"id":35,"rating":"PG"}},{"id":190373,"rating_category":{"id":3,"rating":"E"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/172442.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/172443.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1285102.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1285103.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1285104.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1285105.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1285100.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1285101.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1285107.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1285106.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1285108.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1285109.jpg"]', '{106987,96217,81249,55038,103168,19164,55199,101608,28010,27092}', '{https://www.youtube.com/watch?v=8Ume5pSIcKE,https://www.youtube.com/watch?v=1CSAQ8UxK64}', 'Nintendo', '8', null, '{593}'), (1007, 'Pac-Man: Championship Edition DX', 'PAC-MAN Championship Edition DX continues to uphold NAMCO BANDAI''s tradition of enhancing a classic franchise for today''s gamer. Building upon PAC-MAN Championship Edition’s original six courses, the new game features more than 100 varied and mind-boggling mazes to navigate. Several new modes will also be available to test a player''s pellet-munching aptitude. In Time Attack Mode, players will vie for the quickest clear time. Fulfill a series of objectives in Mission Mode or compete to devour the most number of ghosts gobbled in Ghost Mode.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qx6.jpg', '2010-11-17', '{9,15,33}', 'IGDB', 94.5069035121414, 21737, 1, 17.99, '[{"id":67911,"rating_category":{"id":13,"rating":"A"}},{"id":9913,"rating_category":{"id":3,"rating":"E"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/33242.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/33241.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/33243.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/33240.jpg"]', '{1006,56033,2750,28113,7344,11529,11423,5647,72,5615}', '{https://www.youtube.com/watch?v=lnJ9Op7c_w4}', 'Namco Bandai Games', '10', null, '{8054}'), (1008, 'PlayM2M', 'In PlayM2M, an open-world fantasy online role-playing game, players can choose from four character classes: Dorhan, Skogr, Petrun, and Wizard. Each class has two specializations that offer distinct combat styles for Player vs. Environment (PvE) and Player vs. Player (PvP) modes.

PlayM2M focuses on real-time combat, crafting, exploration, and PvE and PvP content. Currently available in 11 languages, PlayM2M continues to grow with new content and plans for future international expansion.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9l8q.jpg', '2025-03-28', '{12,25}', 'IGDB', 94.4697079574001, 240168, 1, 79.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/265487.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/265485.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/265488.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/265489.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1814892.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1814893.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1814894.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1814895.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1814896.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1814897.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1814898.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1814899.jpg"]', '{54775,103168,106987,96217,113109,113636,81249,19164,55038,55199}', '{https://www.youtube.com/watch?v=3VIGWsFDIJo,https://www.youtube.com/watch?v=IFMJhbDu5cI}', 'Laniatus', '0', null, null), (1009, 'Super Smash Bros. Melee', 'Super Smash Bros. Melee is the second installment in the Super Smash Bros. series and the follow-up to the Nintendo 64 title. It includes all playable characters from the first game, and also adds characters from franchises such as Fire Emblem, of which no games had been released outside Japan at the time. Super Smash Bros. Melee builds on the first game by adding new gameplay features and playable characters: it''s major focus is the multiplayer mode, while still offering a number of single-player modes.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21yv.jpg', '2001-11-21', '{4,8}', 'IGDB', 94.4489587067659, 1627, 1, 22.99, '[{"id":188015,"rating_category":{"id":5,"rating":"T"}},{"id":48850,"rating_category":{"id":31,"rating":"14"}},{"id":49130,"rating_category":{"id":8,"rating":"3"}},{"id":62411,"rating_category":{"id":23,"rating":"ALL"}},{"id":62409,"rating_category":{"id":13,"rating":"A"}},{"id":62412,"rating_category":{"id":35,"rating":"PG"}},{"id":62410,"rating_category":{"id":20,"rating":"12"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/95909.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/259031.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/384038.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/384036.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/384037.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/384034.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/384035.jpg"]', '{21642,27419,55190,1626,24426,56033,14704,20342,28070,55173}', '{https://www.youtube.com/watch?v=649rLYTO8oA,https://www.youtube.com/watch?v=pPpkIitFjvk}', 'Nintendo', '0', null, '{325}'), (1010, 'Arc the Lad II', 'This direct sequel to "Arc the Lad" continues the unfinished story of the first game, but starts from a totally different perspective. You control a bounty-hunter named Elk, who suffers from amnesia. On his quest for his own true identity he discovers the powers hidden within him, and the destiny of his entire tribe. While pursuing his archenemy, Elk meets up with Arc, the hero of the first game, and then both realize they have been looking to destroy the very same evil.

The battle system of "Arc the Lad II" is similar to the one used in its predecessor: in battles you can move your characters on the battle field, and your proximity to the enemies plays an important role. You cause and take different amounts of damage depending on your position on the battle field. Unlike the first game, this one is a full-fledged adventure/RPG, without the "strategy" feel of the predecessor. You move through the game world on your own, visiting towns and exploring dungeons.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co60ah.jpg', '1996-11-01', '{12,15,16,24,31}', 'IGDB', 94.3279114574841, 26345, 1, 16.99, '[{"id":190941,"rating_category":{"id":5,"rating":"T"}},{"id":78713,"rating_category":{"id":23,"rating":"ALL"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/178557.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/387587.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/387586.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/387589.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/387588.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/387594.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/387595.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/387590.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/387592.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/387591.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/387593.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/387596.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/387585.jpg"]', '{26845,22387,14394,1280,13196,115653,25921,55771,660,27092}', '{https://www.youtube.com/watch?v=jVHrUHOm3CY}', 'G-Craft', '0', null, '{2549}'), (1011, 'NextWorld2', 'NextWorld2 is a fantasy MMORPG set in the divided world of Kigan, where two rival kingdoms, Selakim and Quila, struggle for dominance. Players can choose from four classes: Warrior, Shaman, Assassin, and Ezra, and explore a vast open world filled with quests, mounts, dungeons, and large-scale community events.

The game emphasizes real-time combat, crafting, exploration, and both PvE and PvP content. Currently available in Hungary, NextWorld2 has thousands of active players and continues to grow with new content and future international expansion plans.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8gqz.jpg', '2024-07-06', '{12,25}', 'IGDB', 94.2345853956292, 307930, 1, 61.99, '[{"id":223475,"rating_category":{"id":10,"rating":"12"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/213094.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/213095.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/213096.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/213092.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/213093.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/212791.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1351951.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1355830.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1355831.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1355832.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1355833.jpg"]', '{54775,103168,106987,96217,113109,81249,113636,19164,55038,55199}', '{https://www.youtube.com/watch?v=FpfSx72W6xA}', 'Donut Interactive', '0', null, null), (1012, 'The Witcher 3: Wild Hunt - Blood and Wine', 'Blood and Wine is the second major expansion to The Witcher 3: Wild Hunt.

The players will accompany Geralt of Rivia to the region of Toussaint, one of the few places in the Witcher universe which has remained largely untouched by the war. The calm, laid-back atmosphere holds a dark and bloody secret that only the White Wolf can uncover; the expansion features new items for players to collect on their adventure and introduces previously unknown characters.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lgo.jpg', '2016-05-30', '{12,31}', 'IGDB', 94.1978373396272, 13166, 1, 33.99, '[{"id":111643,"rating_category":{"id":17,"rating":"Z"}},{"id":111644,"rating_category":{"id":26,"rating":"19+"}},{"id":111645,"rating_category":{"id":38,"rating":"R 18+"}},{"id":10682,"rating_category":{"id":12,"rating":"18"}},{"id":125671,"rating_category":{"id":22,"rating":"18"}},{"id":63463,"rating_category":{"id":6,"rating":"M"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/170545.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/170547.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/170546.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/25592.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/25594.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/25591.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/25595.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/25593.jpg"]', '{19164,81249,55199,106987,96217,115653,105049,17548,55038,27092}', '{https://www.youtube.com/watch?v=6gpHJWkPYto,https://www.youtube.com/watch?v=rIoPrbzI5Z4,https://www.youtube.com/watch?v=k-QWCiHZPNc,https://www.youtube.com/watch?v=2OOPrprSwC0}', 'CD Projekt RED', '2', null, '{62}'), (1013, 'God of War', 'God of War is the sequel to God of War III as well as a continuation of the canon God of War chronology. Unlike previous installments, this game focuses on Norse mythology and follows an older and more seasoned Kratos and his son Atreus in the years since the third game. It is in this harsh, unforgiving world that he must fight to survive… and teach his son to do the same.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobkt6.jpg', '2018-04-20', '{12,25,31}', 'IGDB', 94.1899683017627, 19560, 1, 32.99, '[{"id":63045,"rating_category":{"id":17,"rating":"Z"}},{"id":222344,"rating_category":{"id":37,"rating":"MA 15+"}},{"id":63046,"rating_category":{"id":26,"rating":"19+"}},{"id":23748,"rating_category":{"id":12,"rating":"18"}},{"id":47579,"rating_category":{"id":22,"rating":"18"}},{"id":187740,"rating_category":{"id":6,"rating":"M"}},{"id":63047,"rating_category":{"id":33,"rating":"18"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/2563.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/2568.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/2564.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/2566.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/2565.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/2567.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1035.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1036.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/2560.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/2561.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/225752.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/225753.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/215543.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/25154.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/25155.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/25153.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/44388.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/44389.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/208198.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/208200.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/208194.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/208195.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/208196.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/208199.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/208197.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1399552.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1399553.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1399554.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1399555.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1399556.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1399557.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1399558.jpg"]', '{112875,26192,19565,11156,105049,76882,55199,7346,112874,9243}', '{https://www.youtube.com/watch?v=Q8-Si4M1b2U,https://www.youtube.com/watch?v=GdJtyZRPsUM,https://www.youtube.com/watch?v=rxrbXP546OU,https://www.youtube.com/watch?v=iLr5BeiTha4,https://www.youtube.com/watch?v=HqQMh_tij0c,https://www.youtube.com/watch?v=CJ_GCPaKywg}', 'Sony Interactive Entertainment', '0', null, '{70}'), (1014, 'Monkey Island Special Edition Collection', 'The Monkey Island Special Edition Collection (abbreviated as MISEC) is a retail release of the Special Editions of the first two Monkey Island games, being The Secret of Monkey Island: Special Edition and Monkey Island 2 Special Edition: LeChuck''s Revenge. As well as all the features presented in the previously released Special Editions, the disc contains never-before-released bonus materials, including concept art for the games, full-length remastered game soundtracks, and the storyboard and concept art for the Monkey Island movie that was in production at one point at ILM.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co26hu.jpg', '2011-10-09', '{2,31}', 'IGDB', 94.1851033628753, 43036, 1, 12.99, '[{"id":90284,"rating_category":{"id":4,"rating":"E10+"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/416284.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/416285.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/416286.jpg"]', '{13189,27725,25222,81275,19164,18011,337432,324525,317311,304068}', '{}', 'LucasArts', '3', null, null), (1015, 'Persona 5 Royal', 'An enhanced version of Persona 5 with some new characters and a third semester added to the game. Released Internationally in 2020.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaqh.jpg', '2019-10-31', '{12,31}', 'IGDB', 94.1289707942737, 114283, 1, 48.99, '[{"id":190473,"rating_category":{"id":6,"rating":"M"}},{"id":79245,"rating_category":{"id":15,"rating":"C"}},{"id":32037,"rating_category":{"id":11,"rating":"16"}},{"id":101952,"rating_category":{"id":26,"rating":"19+"}},{"id":79246,"rating_category":{"id":21,"rating":"16"}},{"id":79247,"rating_category":{"id":32,"rating":"16"}},{"id":224944,"rating_category":{"id":37,"rating":"MA 15+"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/7817.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/7818.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/178913.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/178914.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/219508.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/321050.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/321040.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/321041.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/321042.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/321044.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/321049.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/321048.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/321046.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/321047.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/321045.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/321043.jpg"]', '{19164,27092,55984,26765,26845,22387,25921,17548,96217,116530}', '{https://www.youtube.com/watch?v=IR_7H_zzU7Y,https://www.youtube.com/watch?v=8U8OLRnde70,https://www.youtube.com/watch?v=xHVbI9wjM4U,https://www.youtube.com/watch?v=LFzh6T7bQ_M,https://www.youtube.com/watch?v=o9QjlLdYK5I,https://www.youtube.com/watch?v=GJzcSKyCzZs,https://www.youtube.com/watch?v=91tGkPg1txE,https://www.youtube.com/watch?v=O3dX4tCb_5w,https://www.youtube.com/watch?v=-b2SV5fkQrk,https://www.youtube.com/watch?v=IYsNAxGsaow}', 'Atlus', '10', null, '{552,9216}'), (1016, 'The Legend of Zelda: Tears of the Kingdom', 'An epic adventure across the land and skies of Hyrule awaits in The Legend of Zelda: Tears of the Kingdom for Nintendo Switch. The adventure is yours to create in a world fueled by your imagination.

In this sequel to The Legend of Zelda: Breath of the Wild, you''ll decide your own path through the sprawling landscapes of Hyrule and the mysterious islands floating in the vast skies above. Can you harness the power of Link''s new abilities to fight back against the malevolent forces that threaten the kingdom?', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5vmg.jpg', '2023-05-12', '{9,31}', 'IGDB', 94.1123286944838, 119388, 1, 63.99, '[{"id":226929,"rating_category":{"id":36,"rating":"M"}},{"id":137869,"rating_category":{"id":29,"rating":"10"}},{"id":120927,"rating_category":{"id":24,"rating":"12+"}},{"id":120901,"rating_category":{"id":14,"rating":"B"}},{"id":138146,"rating_category":{"id":10,"rating":"12"}},{"id":189521,"rating_category":{"id":4,"rating":"E10+"}},{"id":138147,"rating_category":{"id":20,"rating":"12"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/168632.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168631.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168630.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168629.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/498357.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/308007.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/498356.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/498355.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/498354.jpg"]', '{7346,19565,28070,9243,19164,17548,19560,55038,10776,105049}', '{https://www.youtube.com/watch?v=3fr1Z07AV00,https://www.youtube.com/watch?v=Pi-MRZBP91I,https://www.youtube.com/watch?v=2SNF4M_v7wc,https://www.youtube.com/watch?v=fYZuiFDQwQw,https://www.youtube.com/watch?v=a6qna-ZCbxA,https://www.youtube.com/watch?v=uHGShqcAHlQ}', 'Monolith Soft', '0', null, '{8988,106}'), (1017, 'MCSR Ranked', 'MCSR Ranked is the best place to learn and play Minecraft speedrunning. Practice with friends, compete for elo, and climb the ranks – First to beat the game wins.', 'https://i