.com/igdb/image/upload/t_1080p/174801.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1010715.jpg"]', '{19565,11156,7346,7331,1074,36926,26761,19164,17548,1905}', '{https://www.youtube.com/watch?v=_GQGUGe7kDU,https://www.youtube.com/watch?v=f8cyFpns0IE,https://www.youtube.com/watch?v=wGQHQc_3ycE,https://www.youtube.com/watch?v=5kcdRBHM7kM}', 'Nintendo', '0', null, '{240}'), (1079, 'FortressOne', 'FortressOne is a free, open source fork of the original 1996 QuakeWorld mod Team Fortress. It is a fast-paced, class based, arena first person shooter remastered with refined graphics, new mechanics and evolved gameplay.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2uk2.jpg', '2018-05-24', '{5}', 'IGDB', 92.8762774218835, 144345, 1, 46.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/61736.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/614699.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/614700.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/614692.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/614693.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/614694.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/614695.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/614696.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/614697.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/614698.jpg"]', '{95340,38030,32902,119177,106805,87622,103302,43367,95308,520}', '{https://www.youtube.com/watch?v=GssbO8BXOAg}', 'FortressOne Team', '12', null, null), (1080, 'Freedom Force vs. The 3rd Reich', 'Freedom is threatened yet again and only Minute Man and his heroic Freedom Force can save the day in the follow up to one of the most critically acclaimed games of 2002.

Freedom Force vs. the Third Reich brings dynamic storytelling, fast-paced tactical role-play, and larger-than-life characters from the comic book pages to the computer screen. In this title, the league of heroes must travel back in time to defeat Blitzkrieg, defender of the Reich and his homicidal henchmen. With action spanning from the blasted battlefields of World War II to the dazzling depths of distant dimensions, Freedom Force vs. the Third Reich will give Freedom Fans more than they can handle.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co28fk.jpg', '2005-03-08', '{12,15,24}', 'IGDB', 92.8611450566907, 721, 1, 26.99, '[{"id":61640,"rating_category":{"id":5,"rating":"T"}},{"id":124092,"rating_category":{"id":20,"rating":"12"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/95535.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/46345.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/46341.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/46342.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/46343.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/46344.jpg"]', '{119598,13196,19404,113402,103232,7615,109339,26845,111187,25311}', '{}', 'Digital Jesters', '0', null, '{167}'), (1081, 'Stream Pairs', 'Stream Pairs is an interactive memory game to play with streaming audience. Use the chat to match pairs by typing the correct position and beat levels by reaching the goals.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4gi8.jpg', '2022-02-04', '{35}', 'IGDB', 92.8571428571429, 191270, 1, 74.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/737775.jpg"]', '{88938,83912,68045,364082,362369,351420,351419,351417,351415,351413}', '{https://www.youtube.com/watch?v=m7uZju5izFs}', 'Onrizon', '0', null, null), (1082, 'God of War Ragnarök', 'God of War: Ragnarök is the ninth installment in the God of War series and the sequel to 2018''s God of War. Continuing with the Norse mythology theme, the game is set in ancient Norway and features series protagonists Kratos, the former Greek God of War, and his young son Atreus. The game kicked off the events of Ragnarök, where Kratos and Atreus must journey to each of the Nine Realms in search of answers as they prepare for the prophesied battle that will end the world.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba3d.jpg', '2022-11-09', '{12,25,31}', 'IGDB', 92.8485674027472, 112875, 1, 66.99, '[{"id":188434,"rating_category":{"id":6,"rating":"M"}},{"id":105532,"rating_category":{"id":22,"rating":"18"}},{"id":112550,"rating_category":{"id":26,"rating":"19+"}},{"id":112549,"rating_category":{"id":17,"rating":"Z"}},{"id":112548,"rating_category":{"id":12,"rating":"18"}},{"id":112551,"rating_category":{"id":33,"rating":"18"}},{"id":105533,"rating_category":{"id":37,"rating":"MA 15+"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/80835.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/176769.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/176770.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/178503.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/615667.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/615668.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/615669.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/615670.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/615671.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/615672.jpg"]', '{19560,105049,103329,26192,112874,19565,11156,7331,3025,1942}', '{https://www.youtube.com/watch?v=EE-4GvjKcfs,https://www.youtube.com/watch?v=g1wr0DfV73E,https://www.youtube.com/watch?v=dIQGI36BxDE,https://www.youtube.com/watch?v=3FwLWwWvNes,https://www.youtube.com/watch?v=4mVaKztSoJM}', 'Sony Interactive Entertainment', '0', '{279623}', '{70}'), (1083, 'Half-Life: Alyx', 'Half-Life: Alyx is Valve’s VR return to the Half-Life series. It’s the story of an impossible fight against a vicious alien race known as the Combine, set between the events of Half-Life and Half-Life 2. Alyx Vance and her father Eli mount an early resistance to the Combine''s brutal occupation of Earth.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co87vg.jpg', '2020-03-23', '{5,9,31}', 'IGDB', 92.8006772915702, 126098, 1, 63.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/8252.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/343809.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/343810.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/343812.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/343811.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/343813.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/343815.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/343814.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/343816.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/343817.jpg"]', '{55038,105269,107318,103301,28070,25646,103292,106805,19164,87622}', '{https://www.youtube.com/watch?v=LTLotwKpLgk,https://www.youtube.com/watch?v=3uKUSnY0HVs,https://www.youtube.com/watch?v=nFjtVmka54E,https://www.youtube.com/watch?v=O2W0N3uKXmo}', 'Valve', '0', null, '{35}'), (1084, 'Disco Elysium: The Final Cut', 'Disco Elysium: The Final Cut is an enhanced edition of the original role-playing game developed and published by ZA/UM. It retains the core gameplay and narrative while adding full voice acting, new quests, additional endings, and other narrative revisions.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ve1.jpg', '2021-03-30', '{12,31,32}', 'IGDB', 92.7998962847108, 141540, 1, 56.99, '[{"id":95626,"rating_category":{"id":16,"rating":"D"}},{"id":126025,"rating_category":{"id":33,"rating":"18"}},{"id":50189,"rating_category":{"id":21,"rating":"16"}},{"id":50190,"rating_category":{"id":38,"rating":"R 18+"}},{"id":60064,"rating_category":{"id":26,"rating":"19+"}},{"id":56175,"rating_category":{"id":12,"rating":"18"}},{"id":46216,"rating_category":{"id":6,"rating":"M"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/168577.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168576.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/185144.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/413554.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/413555.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/413556.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/413557.jpg"]', '{55984,236,80916,109274,1877,17548,55322,96217,106987,79994}', '{https://www.youtube.com/watch?v=ixtTkkEnq0Q,https://www.youtube.com/watch?v=GF8JesUNQVU}', 'ZA/UM', '10', null, null), (1085, 'NetHack', 'NetHack is a single-player roguelike video game originally released in 1987 with ASCII graphics. It is a descendant of an earlier game called Hack, which was inspired by Rogue. The player chooses a character race and class; their mission is to retrieve the Amulet of Yendor in a randomly generated dungeon.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1syp.jpg', '1987-07-28', '{12}', 'IGDB', 92.7840812188957, 2895, 1, 12.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/951049.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/951051.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/951050.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/951052.jpg"]', '{2365,22387,14394,19150,9834,96217,115653,11646,19164,106987}', '{}', null, '12', null, null), (1086, 'Bloodborne: Complete Edition Bundle', 'Bloodborne: Complete Edition Bundle includes Bloodborne full game plus The Old Hunters DLC expansion.

Hunt your nightmares as you search for answers in the ancient city of Yharnam, now cursed with a strange endemic illness spreading through the streets like wildfire. Danger, death and madness lurk around every corner of this dark and horrific world, and you must discover its darkest secrets in order to survive.

Experience the nightmare of the hunters who once protected Byrgenwerth’s darkest secrets and uncover the mystery behind Yharnam’s sinister past in The Old Hunters expansion DLC for Bloodborne.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob7sj.jpg', '2015-11-05', '{12,31}', 'IGDB', 92.7700092659132, 150034, 1, 25.99, '[{"id":36728,"rating_category":{"id":11,"rating":"16"}},{"id":188071,"rating_category":{"id":6,"rating":"M"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/924309.jpg"]', '{106987,96217,81249,116530,103168,55038,101608,19164,28010,111130}', '{}', 'FromSoftware', '3', null, null), (1087, 'The Witcher 3: Wild Hunt', 'The Witcher 3: Wild Hunt is an open-world action role-playing game developed by CD Projekt Red.

Set in a dark fantasy world, the game follows Geralt of Rivia, a monster hunter searching for his adopted daughter, Ciri, while navigating political conflicts and supernatural threats. Gameplay features exploration, combat, character progression, and branching narratives shaped by player choices. Widely acclaimed for its writing, world-building, and depth, it is considered one of the most influential RPGs of its generation.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaarl.jpg', '2015-05-19', '{12,31}', 'IGDB', 92.7605808940297, 1942, 1, 20.99, '[{"id":222156,"rating_category":{"id":38,"rating":"R 18+"}},{"id":32441,"rating_category":{"id":12,"rating":"18"}},{"id":67455,"rating_category":{"id":17,"rating":"Z"}},{"id":78139,"rating_category":{"id":32,"rating":"16"}},{"id":46963,"rating_category":{"id":22,"rating":"18"}},{"id":78138,"rating_category":{"id":26,"rating":"19+"}},{"id":187952,"rating_category":{"id":6,"rating":"M"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/168461.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168459.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168457.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168456.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168455.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168463.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168458.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168460.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168467.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168466.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168465.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168533.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168532.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168464.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168462.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/21107.jpg","https://images.igdb.com/igd