ube.com/watch?v=wHMNQzLG_Jg,https://www.youtube.com/watch?v=unYFdcEjV9k}', 'Sony Interactive Entertainment', '0', null, '{9340}'), (1093, 'Grindstone', 'A puzzle battle adventure. Help Jorj climb Grindstone Mountain and defeat many creeps that try to stop him.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2f2q.jpg', '2019-09-16', '{9,15,32}', 'IGDB', 92.6609808888695, 124031, 1, 30.99, '[{"id":136911,"rating_category":{"id":29,"rating":"10"}},{"id":106914,"rating_category":{"id":24,"rating":"12+"}},{"id":40499,"rating_category":{"id":5,"rating":"T"}},{"id":136913,"rating_category":{"id":21,"rating":"16"}},{"id":136910,"rating_category":{"id":36,"rating":"M"}},{"id":136912,"rating_category":{"id":9,"rating":"7"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/15343.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/336227.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/336226.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/336225.jpg"]', '{65827,19404,31515,36269,18623,121518,17111,27266,23345,29173}', '{https://www.youtube.com/watch?v=z2UcjL7gc78,https://www.youtube.com/watch?v=26UtmuqU37Q}', 'Capybara Games', '0', null, null), (1094, 'The Last of Us Part II', 'The Last of Us Part II is an action-adventure game set five years after the events of The Last of Us. The player traverses post-apocalyptic environments such as buildings and forests to advance the story. They can use firearms, improvised weapons, and stealth to defend against hostile humans and cannibalistic creatures infected by a mutated strain of the Cordyceps fungus. The game intermittently switches control between Ellie and Abby, and also briefly Joel in the opening sequence. The nimble nature of the player character introduces platforming elements, allowing the player to jump and climb to traverse environments and gain advantages during combat.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ziw.jpg', '2020-06-19', '{5,31}', 'IGDB', 92.6288059062172, 26192, 1, 67.99, '[{"id":47780,"rating_category":{"id":17,"rating":"Z"}},{"id":47782,"rating_category":{"id":26,"rating":"19+"}},{"id":47781,"rating_category":{"id":22,"rating":"18"}},{"id":47783,"rating_category":{"id":33,"rating":"18"}},{"id":47784,"rating_category":{"id":38,"rating":"R 18+"}},{"id":47779,"rating_category":{"id":12,"rating":"18"}},{"id":189552,"rating_category":{"id":6,"rating":"M"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/168689.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168687.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168690.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168688.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/34675.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/396903.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/396904.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/396905.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/396906.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/396907.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/34674.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/34673.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/34677.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/214555.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/214556.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/214557.jpg"]', '{19564,19561,37016,102584,11156,13210,105049,44076,19565,17379}', '{https://www.youtube.com/watch?v=muniWyT4vTg,https://www.youtube.com/watch?v=HfxOtvmpsM8,https://www.youtube.com/watch?v=t-BUJoqZRsw,https://www.youtube.com/watch?v=mRj3B3GY9KM,https://www.youtube.com/watch?v=ArAdN5ilVRs,https://www.youtube.com/watch?v=gF1EQAtaZEo,https://www.youtube.com/watch?v=II5UsqP2JAk,https://www.youtube.com/watch?v=jziBvTUdCB0}', 'Sony Interactive Entertainment', '0', null, '{864}'), (1095, 'Gloam', 'In Gloam, the player embodies a small candle which must in order to survive, steal light from other players. The confrontation is done via mini-games of logic and speed. The last of the 10 participants to still have the light wins.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2u6x.jpg', '2021-03-01', '{32,33}', 'IGDB', 92.5925925925926, 144133, 1, 54.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/20013.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/424461.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/424462.jpg"]', '{43367,87514,18981,113895,90965,38967,25640,121036,56033,119207}', '{https://www.youtube.com/watch?v=NwYzPByF-Ck}', 'CORDYLUS', '0', null, null), (1096, 'Hrot', 'Hrot is a single-player retro FPS set in a small socialist country neighboring Soviet Union (Czechoslovakia) after an unspecified disaster in 1986. Those times were dark and terrifying and so is the game.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2omv.jpg', '2023-05-16', '{5,32}', 'IGDB', 92.576187069726, 135478, 1, 65.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/39101.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/390541.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/390542.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/390545.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/390548.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/390543.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/390544.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/390547.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/390546.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1372798.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1372799.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1372800.jpg"]', '{111130,32902,113895,25646,43367,520,105269,68271,107318,26658}', '{https://www.youtube.com/watch?v=FX2oINMwoJk}', 'Spytihněv', '0', null, null), (1097, 'Mass Effect Trilogy', 'Experience all three award winning Mass Effect titles at an amazing value with the Mass Effect Trilogy.

As Commander Shepard, rise to become the galaxy’s most elite soldier and lead an all-out war to stop an ancient and ruthless enemy: the Reapers. With over 75 hours of content and more than 300 awards, one of gaming’s most acclaimed franchises is available for the first time in a premium foiled box set.

Heart-pounding action meets gripping interactive storytelling where you decide how your unique story unfolds. Assemble and lead your team aboard the SSV Normandy, the most advanced ship in the galaxy, and travel to distant and unexplored star systems. On your journey, meet a cast of intriguing characters each with their own story to tell. Wield devastating weapons and customize them with upgrades to create new and devastating attacks. All the thrilling action and your decisions culminate into a heroic battle against the greatest threat ever known.

The fate of the galaxy lies in your hands—how will you chose to fight for it?', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4a7a.jpg', '2012-11-06', '{5,12,31}', 'IGDB', 92.5498154007898, 45181, 1, 14.99, '[{"id":192317,"rating_category":{"id":12,"rating":"18"}},{"id":192321,"rating_category":{"id":37,"rating":"MA 15+"}},{"id":192316,"rating_category":{"id":6,"rating":"M"}},{"id":192318,"rating_category":{"id":21,"rating":"16"}},{"id":192320,"rating_category":{"id":31,"rating":"14"}},{"id":192319,"rating_category":{"id":26,"rating":"19+"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/213497.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/213498.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/213499.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/213500.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1684862.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1684863.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1684864.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1684865.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1684866.jpg"]', '{105269,55038,107318,36950,19164,25311,103301,76877,106987,28309}', '{https://www.youtube.com/watch?v=u3q-YzQfkmM}', 'BioWare', '3', null, '{25}'), (1098, 'Knytt Stories', 'Knytt Stories is a platform game consisting of five original shorter stories about Knytts in their universe and hundreds of custom made stories.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co28f1.jpg', '2007-09-30', '{8}', 'IGDB', 92.5455910390569, 51317, 1, 5.99, '[]', '[]', '[]', '{63138,77349,12539,119199,124565,20342,55173,24426,28070,55190}', '{}', 'Nicklas Nygren', '0', null, '{3794}'), (1099, 'Resident Evil 4', 'Resident Evil 4 is a remake of the 2005 original Resident Evil 4 reimagined for 2023 to bring state-of-the-art survival horror. Resident Evil 4 preserves the essence of the original game, while introducing modernized gameplay, a reimagined storyline,
and vividly detailed graphics to make this the latest survival horror game where life and death, terror and catharsis intersect.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bo0.jpg', '2023-03-24', '{5,9,31}', 'IGDB', 92.504913149171, 132181, 1, 59.99, '[{"id":226781,"rating_category":{"id":38,"rating":"R 18+"}},{"id":130639,"rating_category":{"id":12,"rating":"18"}},{"id":130640,"rating_category":{"id":22,"rating":"18"}},{"id":130578,"rating_category":{"id":26,"rating":"19+"}},{"id":130638,"rating_category":{"id":17,"rating":"Z"}},{"id":106109,"rating_category":{"id":33,"rating":"18"}},{"id":189460,"rating_category":{"id":6,"rating":"M"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/90066.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/803216.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/803217.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/803218.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/803219.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/883848.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/883849.jpg"]', '{114455,19817,18225,105049,18020,25646,103329,37016,28552,56033}', '{https://www.youtube.com/watch?v=cMzJv0LOJYo,https://www.youtube.com/watch?v=9p0YVZy2hXI,https://www.youtube.com/watch?v=rcFarJACzx0,https://www.youtube.com/watch?v=17lHF8U_du8,https://www.youtube.com/watch?v=bwxMrAy4z-s}', 'Capcom Development Division 1', '8', '{242726}', '{83}'), (1100, 'Spatial', 'Spatial is a 3D gaming hub where creators craft and share immersive social experiences for web, mobile, and VR. We''re transforming online interaction from passive watching to active play. Think YouTube, but for games.

From Racing Empire to Merge Survivor Zombie, there are thousands of games that can be discovered on Spatial. And with the Spatial Creator Toolkit, developers can build and publish their own games to a community of millions of players, to the library of games is growing every day.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co83m1.jpg', '2020-03-15', '{8}', 'IGDB', 92.5, 298274, 1, 74.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1306513.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1306514.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1306515.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1306516.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1306517.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1306518.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1306519.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1306520.jpg"]', '{119199,140903,130683,17269,103328,51485,28751,77349,38967,131411}', '{https://www.youtube.com/watch?v=DdMIZqR3mmA,https://www.youtube.com/watch?v=M-4dkVptPRk,https://www.youtube.com/watch?v=rBtMW5e5wJU,https://www.youtube.com/watch?v=4jqQlVAVNIM,https://www.youtube.com/watch?v=r0jjUgjFqQA,https://www.youtube.com/watch?v=r7pG3BrerbM,https://www.youtube.com/watch?v=YeAlw6sB_4c}', 'Spatial Systems', '0', null, null), (1101, 'One Btn Bosses', 'It''s One Button Bosses, it''s all in the name. You have one button. There are big bosses to beat. Push, tap, and bash in the handcrafted campaign or in the roguelike rifts.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8m8x.jpg', '2024-08-06', '{32,33}', 'IGDB', 92.5, 197067, 1, 60.99, '[{"id":205762,"rating_category":{"id":3,"rating":"E"}},{"id":205139,"rating_category":{"id":8,"rating":"3"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/74008.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1374217.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1374219.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1374215.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1374216.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1374218.jpg"]', '{23733,11646,11182,14593,26820,76263,109550,18182,20329,109129}', '{https://www.youtube.com/watch?v=WldHLxkAW5g}', 'Midnight Munchies', '0', null, null), (1102, 'Rising Star', 'Free to play NFT based music career game. Earn crypto and become a megastar!
Start as a lowly busker and work your way to the world tour collecting NFTs and earning crypto along the way. See you in Buskeria!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ch0.jpg', '2020-04-15', '{35}', 'IGDB', 92.4882629107981, 187043, 1, 60.99, '[]', '[]', '[]', '{235170,218843,235339,247500,246145,235261,221385,212568,205169,126094}', '{}', null, '0', null, null), (1103, 'Starsector', 'Starsector is a game of space combat, fleet management, trade, and role-playing. Pilot a ship and command a fleet through intense tactical combat while exploring, trading, battling, and leveling-up in an open-ended sandbox campaign set in a lost sector of the galaxy.

Explore distant star systems. Trade goods and loyalty among competing factions. Beware of ruthless pirates while evading tariff patrols. Assemble your fleet for trade or battle while upgrading and modify your starships, then fight your enemies!

Forge your destiny and steer the fate of the human race 6000 light-years from Old Earth.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/iitmusvztmuys7atbe88.jpg', '2013-04-26', '{13,32}', 'IGDB', 92.450430228208, 18349, 1, 9.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/21772.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/21773.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/21774.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/21775.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/21776.jpg"]', '{34823,37419,51577,13200,111187,25311,17130,11666,26574,47823}', '{https://www.youtube.com/watch?v=cbjPgePY4HU}', 'Fractal Softworks', '0', null, null), (1104, 'The Binding of Isaac: Repentance', 'The Binding of Isaac: Repentance is the ultimate edition of the award-winning roguelike twin-stick shooter. It includes all the content from previous editions of The Binding of Isaac (Rebirth, Afterbirth and Afterbirth+) plus Repentance, the game''s final and biggest-ever expansion, adding hundreds of additional new features, modes, and improvements. Experience the modern classic like it''s never been seen before!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5uz8.jpg', '2021-03-31', '{5,12,31,32,33}', 'IGDB', 92.4377810527221, 228374, 1, 50.99, '[{"id":133010,"rating_category":{"id":25,"rating":"15+"}},{"id":133006,"rating_category":{"id":11,"rating":"16"}},{"id":133009,"rating_category":{"id":37,"rating":"MA 15+"}},{"id":133008,"rating_category":{"id":21,"rating":"16"}},{"id":133007,"rating_category":{"id":30,"rating":"12"}},{"id":107712,"rating_category":{"id":15,"rating":"C"}},{"id":110087,"rating_category":{"id":6,"rating":"M"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/95593.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/95594.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/95590.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/95592.jpg","https://images.igdb.c