.com/igdb/image/upload/t_1080p/1687671.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1687667.jpg"]', '{77529,89074,114145,283992,264472,229119,185937,134908,78109,20342}', '{}', 'chroda.eu', '0', null, '{13030}'), (1108, 'Super Sorry', 'You play as a salaryman who gets caught in various everyday troubles and overcomes them with acrobatic bows. From boss reprimands to client complaints and family issues, showcase your elegant apology skills across different scenarios. What shocking ending awaits?', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaraa.jpg', '2025-01-20', '{13,32}', 'IGDB', 92.3809523809524, 326089, 1, 79.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/212795.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/150877.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1438334.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1438335.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1438337.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1438340.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1438342.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1438343.jpg"]', '{17130,37419,109550,36553,105011,109129,25311,35994,38967,29783}', '{https://www.youtube.com/watch?v=XHC6qDFI51E}', 'Sun Studios', '0', null, null), (1109, 'Tetris DX', 'Tetris DX has everything you need to satisfy your puzzle appetite. Play marathon, the classic Tetris game. Try your hand at ultra or 40 lines, two Tetris games with a twist. The vs. game will have you playing for hours!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3a6u.jpg', '1998-10-21', '{9,15}', 'IGDB', 92.36934043924, 49875, 1, 16.99, '[{"id":19763,"rating_category":{"id":3,"rating":"E"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/334269.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/334268.jpg"]', '{3655,17111,78550,109129,73946,21166,79080,72044,4200,49155}', '{}', 'Nintendo', '10', null, '{516}'), (1110, 'Mario Kart 8 Deluxe: Booster Course Pass', 'A total of 48 more courses from throughout the Mario Kart series are racing to the Mario Kart 8 Deluxe game as paid DLC*. Take in the sights and speed through courses based on real-world locations like Tour London Loop and Tour New York Minute. This DLC also brings back half-pipes! Get some air, pull off a trick, and get a speed boost on Merry Mountain and Wii Maple Treeway.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co67uo.jpg', '2022-03-18', '{10}', 'IGDB', 92.3624736867267, 191419, 1, 59.99, '[{"id":67141,"rating_category":{"id":3,"rating":"E"}},{"id":100827,"rating_category":{"id":13,"rating":"A"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/74916.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/738338.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/738339.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/863130.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/863129.jpg"]', '{109292,55192,104983,44178,80382,27553,107227,102023,27378,396794}', '{https://www.youtube.com/watch?v=1uZDbDoDAq4}', 'Nintendo', '3', null, null), (1111, 'The Witcher 3: Wild Hunt - Complete Edition', 'The Witcher 3: Wild Hunt – Complete Edition is a comprehensive release that includes the base game, both major expansions (Hearts of Stone and Blood and Wine), and all free DLCs. It has been issued in multiple versions over time:

- 2016 (PC, PS4, Xbox One): Released alongside the Game of the Year Edition, functionally identical but branded differently depending on region.

- 2022 (PS5, Xbox Series X|S, PC): Updated version including the next-gen enhancements, such as ray tracing, visual upgrades, and quality-of-life improvements, plus additional content inspired by the Netflix series.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5uct.jpg', '2016-08-29', '{12,31}', 'IGDB', 92.3551405857355, 119402, 1, 52.99, '[{"id":29884,"rating_category":{"id":12,"rating":"18"}},{"id":29883,"rating_category":{"id":6,"rating":"M"}},{"id":95294,"rating_category":{"id":26,"rating":"19+"}},{"id":96433,"rating_category":{"id":17,"rating":"Z"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/168534.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/7515.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/308167.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/308166.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/308168.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/308160.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/308163.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/308162.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/308164.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/308161.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/308165.jpg"]', '{81249,19164,55199,106987,96217,115653,17548,55038,105049,103168}', '{https://www.youtube.com/watch?v=8cdP-JseTK0,https://www.youtube.com/watch?v=BAC-jqZTCv8,https://www.youtube.com/watch?v=nBT2SP21f3Q,https://www.youtube.com/watch?v=egg9jUkHxQc,https://www.youtube.com/watch?v=OWlkp2qImuI,https://www.youtube.com/watch?v=TWOkT7l0yWQ}', 'Saber Interactive', '3', null, null), (1112, 'Underhell', 'Underhell is a Source Engine game developed by the Underhell Team in collaboration with We Create Stuff. Underhell Chapter 1 requires ONLY Source SDK Base 2007 installed. No Source game is required.

Underhell is split in 3 different zones.

The first is "The House". Each new chapter will have its own version of The House with different puzzles, mysteries to discover, and diary pages of Jake''s late wife to be found.
The second is "The Dreams". With each new version of The House will come a set of dreams. They can be accessed by sleeping in the bed during the night.

Dreams will give you bits of information about the story. They are very different from the rest of the game in both their narrative and gameplay, and focus mostly on exploration and solving puzzles.

The Dreams are not bound by earthly rules and have a few twists to them that will challenge the player.

The third is "The Chapters" where the main storyline of Underhell takes place. You can access a chapter from The House, and when it is completed, you are sent back to The House.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1nib.jpg', '2011-03-05', '{5,31}', 'IGDB', 92.3221593926708, 121214, 1, 14.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1355706.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1355707.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1355708.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1355709.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1355710.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1355712.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1355714.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1355715.jpg"]', '{111130,55282,13189,27266,106805,87622,25646,25222,520,87514}', '{https://www.youtube.com/watch?v=z1ihwoGVijE,https://www.youtube.com/watch?v=j5_nfI-jadk,https://www.youtube.com/watch?v=vJuw8uuG2Jc}', 'Mxthe', '5', null, null), (1113, 'Ultimate Fighting Championship', 'The Ultimate Fighting Championship tournaments started in the 1990s, giving martial artists of the world a chance to distinguish themselves in a fighting environment with very few rules. Fighters could be matched up against fighters of any style, and the match ended only when one fighter submitted.

The popularity of the sport resulted in the creation of other mixed martial arts tournaments and the evolution and merging of fighting styles for greater effectiveness. Ultimate Fighting Championship is a 3D fighting game that tries to simulate the experience of a real mixed martial arts fight. Players can choose from a selection of established UFC fighters, or create their own fighter through the Career Mode.

While in Career Mode, players start the character creation process by selecting from several style templates, then using points earned through fighting and beating a series of progressively more difficult fighters to buy attribute upgrades in stamina, endurance, punching ability, kicking ability, or to learn certain techniques.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3g8w.jpg', '2000-08-30', '{4,14}', 'IGDB', 92.3187927942732, 24176, 1, 9.99, '[{"id":73057,"rating_category":{"id":5,"rating":"T"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1035736.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1035737.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1035738.jpg"]', '{89550,76064,101608,14704,105049,118871,4787,15851,114285,5867}', '{https://www.youtube.com/watch?v=kdaqipplAr8}', null, '0', null, '{687}'), (1114, 'The Last of Us', 'The Last of Us is a third-person action-adventure game featuring a mix of exploration, stealth and combat. Players face both infected creatures and hostile human enemies while progressing through varied environments. The game includes a narrative-driven single-player campaign and a competitive online multiplayer mode called Factions. Trophy support is included, and additional downloadable content was made available separately.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1r7f.jpg', '2013-06-14', '{5,31}', 'IGDB', 92.2733245767785, 1009, 1, 7.99, '[{"id":189700,"rating_category":{"id":6,"rating":"M"}},{"id":47771,"rating_category":{"id":26,"rating":"19+"}},{"id":23999,"rating_category":{"id":12,"rating":"18"}},{"id":47772,"rating_category":{"id":32,"rating":"16"}},{"id":47773,"rating_category":{"id":38,"rating":"R 18+"}},{"id":47770,"rating_category":{"id":22,"rating":"18"}},{"id":47769,"rating_category":{"id":17,"rating":"Z"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/168633.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168641.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168637.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168642.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168636.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168634.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168638.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168639.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/168635.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/258405.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/258406.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/259431.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/259432.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/259433.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1570246.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1570247.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1570248.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1570249.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1570250.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1570251.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1570252.jpg"]', '{1020,533,1985,19441,538,1121,1164,3025,960,20}', '{https://www.youtube.com/watch?v=fxeNaDjU7sw,https://www.youtube.com/watch?v=0hUN_2vS8Ic,https://www.youtube.com/watch?v=0a4IRU2h2N8,https://www.youtube.com/watch?v=uaQQJwZpswQ,https://www.youtube.com/watch?v=PTTvQf5BRPw,https://www.youtube.com/watch?v=UBshR1qD3oU,https://www.youtube.com/watch?v=M5y03s0-Bbk,https://www.youtube.com/watch?v=LH18nGoIUKo,https://www.youtube.com/watch?v=OQpdSVF_k_w,https://www.youtube.com/watch?v=8ZYkj0glnqs}', 'Naughty Dog', '0', null, '{864}'), (1115, 'Chrono Trigger', 'In this turn-based Japanese RPG, young Crono must travel through time through a misfunctioning teleporter to rescue his misfortunate companion and take part in an intricate web of past and present perils. The adventure that ensues soon unveils an evil force set to destroy the world, triggering Crono''s race against time to change the course of history and bring about a brighter future.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3plw.jpg', '1995-03-11', '{12}', 'IGDB', 92.2719572225101, 1802, 1, 28.99, '[{"id":8773,"rating_category":{"id":10,"rating":"12"}},{"id":192330,"rating_category":{"id":23,"rating":"ALL"}},{"id":192329,"rating_category":{"id":19,"rating":"6"}},{"id":189637,"rating_category":{"id":4,"rating":"E10+"}},{"id":76150,"rating_category":{"id":13,"rating":"A"}},{"id":192331,"rating_category":{"id":35,"rating":"PG"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/229122.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266027.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266028.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266041.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266030.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266031.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266032.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266033.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266034.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266035.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266036.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266042.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266043.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266044.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266045.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266037.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266038.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266039.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266040.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/266029.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/24632.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/154943.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/24631.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/24630.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/24633.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/154941.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/154942.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/154944.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/154946.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/154945.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/154947.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1522739.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1522738.jpg"]', '{26845,22387,19164,115653,1877,55038,105049,18812,2449,14394}', '{https://www.youtube.com/watch?v=pzIxOja_Y7w,https://www.youtube.com/watch?v=nRF0SjS4wE0}', 'Bird Studio', '0', null, '{345}'), (1116, 'Castlevania: Symphony of the Night', 'Having been awoken from his eternal slumber by the reappearance of Castlevania, Alucard must once again face the evil minions of darkness. Use your vampiric powers, along with weapons, potions, and other magical relics to change the tide of battle.

A mixture of platform and role-playing action with many hidden areas and secrets. Can you discover them all?', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co53m8.jpg', '1997-03-20', '{8,12,31}', 'IGDB', 92.2632736906163, 1128, 1, 10.99, '[{"id":32965,"rating_category":{"id":10,"rating":"12"}},{"id":146437,"rating_category":{"id":30,"rating":"12"}},{"id":125579,"rating_category":{"id":20,"rating":"12"}},{"id":108657,"rating_category":{"id":15,"rating":"C"}},{"id":108655,"rating_category":{"id":25,"rating":"15+"}},{"id":106287,"rating_category":{"id":5,"rating":"T"}},{"id":88131,"rating_category":{"id":35,"rating":"PG"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/77156.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/77155.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/77153.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/236687.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/236695.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/236692.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/236689.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/236684.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/236685.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/236686.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/236688.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/236690.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/236691.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/236693.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/236694.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/9292.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/9291.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/818391.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/818392.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/818393.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/818394.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/837383.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1645369.jpg"]', '{1134,551,1879,832,1114,3349,3025,1130,1020,1105}', '{https://www.youtube.com/watch?v=mG6-3Dthsy0}', 'Konami Computer Entertainment Tokyo', '0', null, '{65,11004}'), (1117, 'Gran Turismo 3: A-Spec', 'More than two years in the making, Gran Turismo 3 A-spec features over 150 detailed cars -- each composed of more than 4,000 polygons -- 60 beginner, amateur and professional championship races, as well as ten endurance races and ten rally races. In addition to all-new special effects, such as sun glare, heat distortion and reflections, Gran Turismo 3 A-spec also offers up a soundtrack of more than 20 licensed tracks, and an even better replay mode with TV-style camera views. Two players can go head-to-head via split-screen and up to six can duke it out by linking multiple systems together via i.LINK. Released worldwide in 2001, Gran Turismo 3 a-Spec was designed by Polyphony Digital.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5xru.jpg', '2001-04-28', '{10,13}', 'IGDB', 92.2632330975452, 1600, 1, 13.99, '[{"id":4604,"rating_category":{"id":3,"rating":"E"}},{"id":29954,"rating_category":{"id":8,"rating":"3"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/398754.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398743.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398744.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398745.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398746.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398747.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398748.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398749.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398750.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398751.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398753.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/12260.jpg"]', '{1594,78511,1597,96,97,3073,3068,98,5928,100}', '{https://www.youtube.com/watch?v=3n1WTytK1Dw}', 'Polyphony Digital', '0', null, '{323}'), (1118, 'Silent Hill 2', 'This version of Silent Hill 2 is a remaster included in the Silent Hill HD Collection. The graphics have been re-mastered to 720p, the in-game voice-over was updated along with a re-mastering of the soundtrack and achievements/trophies were added.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5wkr.jpg', '2012-03-20', '{9,31}', 'IGDB', 92.2523761324933, 222485, 1, 17.99, '[{"id":100389,"rating_category":{"id":6,"rating":"M"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/907411.jpg"]', '{18011,55984,25646,25222,27266,27725,26223,11668,18225,81275}', '{}', 'Hijinx Studios', '9', null, '{63}'), (1119, 'Ashen Sky', 'Inspired by the thrilling, mystical and at the same time exciting and adventurous worlds of the Roadside Picnic novel, Stalker movie and, of course, famous S.T.A.L.K.E.R. games, Ashen Sky aims to recreate the sensation of being face to face with the vast unknown. The gameplay is harsh and combat is unforgiving, since casual shootouts without serious consequences are not what this codebase aims for; instead, it is about working in teams with different specializations between players as every character has a set of traits that define their parameters, in order to survive, uncover the secrets of the anomalous territories and learn how to make use and profit of your knowledge. It''s about being all alone with the absolutely uncaring, alien Zone - one where no admin will magically help you if you get killed by another player, where there are no rules, yet the game punishes playing dumb and aggressive, and the best strategy is being smart and patient.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co856i.jpg', '2019-05-27', '{12,31,32}', 'IGDB', 92.2330097087379, 299596, 1, 51.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/262279.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/262280.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1807921.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1807922.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1807923.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1807924.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1807925.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1807926.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1807927.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1807928.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1807929.jpg"]', '{17548,26574,10776,80916,113360,25300,106987,10032,37419,47823}', '{https://www.youtube.com/watch?v=jyEM0KED_xA}', null, '0', null, null), (1120, 'Donkey Kong Bananza', 'Donkey Kong Bananza is exclusively on Nintendo Switch 2! Explore a vast underground world—by smashing your way through it! Bash, throw, and climb through just about anything in DK’s brand-new 3D platforming action-adventure game!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobd1q.jpg', '2025-07-17', '{8,31}', 'IGDB', 92.2265467163891, 338106, 1, 83.99, '[{"id":208057,"rating_category":{"id":9,"rating":"7"}},{"id":208058,"rating_category":{"id":13,"rating":"A"}},{"id":208059,"rating_category":{"id":28,"rating":"L"}},{"id":208061,"rating_category":{"id":19,"rating":"6"}},{"id":209678,"rating_category":{"id":4,"rating":"E10+"}},{"id":222147,"rating_category":{"id":35,"rating":"PG"}},{"id":215850,"rating_category":{"id":23,"rating":"ALL"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/159356.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/159357.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/172645.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/172657.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/159355.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1496759.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1496760.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1496761.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1496762.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1496763.jpg"]', '{1074,103329,81680,55190,56033,24426,28070,20342,55173,19150}', '{https://www.youtube.com/watch?v=LOvkfpenFtg,https://www.youtube.com/watch?v=Z6faq_QW_U8,https://www.youtube.com/watch?v=mIddsPkdX9U,https://www.youtube.com/watch?v=YVUidGTR8xg,https://www.youtube.com/watch?v=bG2u334HfFc,https://www.youtube.com/watch?v=JaQSLGiEd3U}', 'Nintendo', '0', '{366892}', '{242}'), (1121, 'Virtual Pool 3', 'Women''s Professional Billiard Association''s star sensation Jeanette Lee teams up with developer Celeris, Inc. to create the third installation of the Virtual Pool series by publisher Interplay. Featuring a new single player mode and online gaming capabilities to accommodate multiplayer action over a LAN or a modem, Virtual Pool 3 Featuring Jeanette Lee continues the tradition that made previous installments a commercial success.

The game offers numerous game modes from which to choose, including a career mode that allows you to begin as a local player and move up through six stages on the proverbial success ladder. You can also play head-to-head against Jeanette Lee (aka "Black Widow"), adjust camera angles, set up shots, play in a tournament with 4, 8, 16 or 32 players and choose from 9-ball, 8-ball, straight pool and several other game configurations.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9xop.jpg', '2000-11-14', '{14}', 'IGDB', 92.2233232257509, 938, 1, 21.99, '[{"id":65731,"rating_category":{"id":3,"rating":"E"}}]', '[]', '[]', '{116353,235341,88273,4073,4072,116352,114286,116350,116349,116351}', '{}', 'Interplay Entertainment', '0', null, null), (1122, 'Arma Reforger', 'Powered by the new Enfusion engine, Arma Reforger lets you fight for supremacy over 51 km2 of incredible island terrain in an authentic Cold War setting, or create unique scenarios in real-time with the Game Master curation mode. Return to Everon, the war-driven microstate from the hit game that started it all, Arma: Cold War Assault.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa97g.jpg', '2023-11-16', '{5,13,15,24}', 'IGDB', 92.2222222222222, 201789, 1, 71.99, '[{"id":194813,"rating_category":{"id":6,"rating":"M"}},{"id":178980,"rating_category":{"id":11,"rating":"16"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/186057.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/186058.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/796784.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/796785.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/796786.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/796787.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/796788.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/796789.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/796790.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/796791.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/796792.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/796793.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/796794.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/796795.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1381093.jpg"]', '{26574,8422,17379,37419,15536,19549,44076,36258,118218,58075}', '{https://www.youtube.com/watch?v=AIervYhiEZ8,https://www.youtube.com/watch?v=vAY9i2RG5Fc}', 'Bohemia Interactive', '0', null, '{117}'), (1123, 'The Ico & Shadow of the Colossus Collection', 'The Ico & Shadow of the Colossus Collection is a video game bundle that contains high-definition remasters of two older PlayStation 2 games for the PlayStation 3, and was developed by Bluepoint Games and released alongside Ico as The Ico & Shadow of the Colossus Collection in September 2011.

The Collection features:
- High-definition (HD) graphics
- Content previously missing from the North American release
- PlayStation Network Trophies
- 3D support.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ako.jpg', '2011-09-22', '{13,31}', 'IGDB', 92.2016081917686, 21084, 1, 23.99, '[{"id":29924,"rating_category":{"id":5,"rating":"T"}},{"id":29925,"rating_category":{"id":10,"rating":"12"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/9789.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/9788.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/9786.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/9787.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/398558.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398557.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398556.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398555.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398554.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398553.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398552.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398562.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398561.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398560.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/398559.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/29018.jpg"]', '{81249,19164,26574,106987,37419,96217,55984,115653,17548,62151}', '{https://www.youtube.com/watch?v=eo0k0q7X47w}', 'Team Ico', '3', null, null), (1124, 'The Settlers II: Gold Edition', 'The goal of this game is to build a prosperous and well-organized city and to gain control of the enemy cities. This might initially seem simple to do, but in reality, it is much more complex. Settlers II is much more complex and with better graphics than the original Settlers game. The Gold Edition features the original game and the Mission CD expansion.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co67o6.jpg', '1997-08-01', '{11,13,15}', 'IGDB', 92.1890896875475, 2617, 1, 17.99, '[{"id":27816,"rating_category":{"id":9,"rating":"7"}},{"id":78303,"rating_category":{"id":3,"rating":"E"}},{"id":123532,"rating_category":{"id":19,"rating":"6"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/22965.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/383044.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/383046.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/383045.jpg"]', '{20776,55036,55590,3067,36346,31515,31480,18623,17111,23345}', '{https://www.youtube.com/watch?v=jYQuiJIH98Q}', 'Blue Byte Software', '3', null, '{619}'), (1125, 'From the Depths', 'In From the Depths you can build and take first-person command of battleships, planes, submarines, space ships, hot air balloons and more! The game contains a wide range of single player content including:
A creative mode allowing you to push your designs to the limit and ensure the total annihilation of your opponents.
A strategic campaign waged over hundreds of islands against eight unique factions.
A Story Mode where you can play missions as each of the eight factions - a fantastic mixture of strategy, design and wild battles! Defend your fleet against waves of enemy forces in a series of extremely tough challenges.
Adventure mode where you start on a raft and must build up your fleet and travel a dangerous universe fighting or running from enemy fleets

As well as a wide range of multiplayer content
Design with your friends in co-op designer
Play a range of adversarial modes
Play the entire single player campaign together in co-op', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2k0e.jpg', '2020-11-06', '{12,13,15,31,32}', 'IGDB', 92.1884396926161, 9632, 1, 58.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/30029.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/407196.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/407197.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/407198.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/407199.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/407200.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/407201.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/407202.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/407203.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/407204.jpg"]', '{25311,35994,10776,26574,28309,17379,80916,105269,109339,25300}', '{}', 'Brilliant Skies Ltd.', '0', null, null), (1126, 'Cyberpunk 2077: Ultimate Edition', 'Cyberpunk 2077: Ultimate Edition is an open-world RPG containing two powerful adventures: the base game of Cyberpunk 2077, taking place in the dark future of Night City, and Phantom Liberty, a spy-thriller story set in the walled-off district of Dogtown. Players take on the role of V, a cyber-enhanced mercenary, and embark on a fight for survival filled with story-defining decisions, action-packed gameplay, and unforgettable characters, including rockerboy Johnny Silverhand (played by Keanu Reeves) and FIA sleeper agent Solomon Reed (played by Idris Elba).

This new release is the perfect way to experience every story of the dark future; it also contains the free Update 2.0, which overhauled many of the game’s systems, introducing dynamic skill trees, high-octane vehicle combat, and enhanced enemy and police AI — as well as adding new weapons, vehicles, and clothes. The release is bolstered with a set of previously released digital goodies available as part of the “My Rewards” program, available to all who register.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7iy1.jpg', '2023-09-26', '{5,12,31}', 'IGDB', 92.1813811546799, 277807, 1, 76.99, '[{"id":222157,"rating_category":{"id":38,"rating":"R 18+"}},{"id":161600,"rating_category":{"id":22,"rating":"18"}},{"id":161604,"rating_category":{"id":12,"rating":"18"}},{"id":166408,"rating_category":{"id":33,"rating":"18"}},{"id":161605,"rating_category":{"id":26,"rating":"19+"}},{"id":161602,"rating_category":{"id":17,"rating":"Z"}},{"id":161599,"rating_category":{"id":6,"rating":"M"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/170543.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/170542.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/127736.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1204267.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1204270.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1204272.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1204274.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1204276.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1204278.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1204280.jpg"]', '{19164,55038,105269,1877,107318,26574,54842,47823,100413,17548}', '{https://www.youtube.com/watch?v=7B4r1jbpS2A,https://www.youtube.com/watch?v=Ugb80d5lxEM,https://www.youtube.com/watch?v=iRswiS_NvgA}', 'CD Projekt RED', '3', null, null), (1127, 'Auf Wiedersehen Monty', 'Monty On the Run is a platform-style game featuring Monty Mole, a coal thief fleeing across Europe to escape the Intermole agency. Players navigate Monty through 80 screens representing European landmarks, using various movement techniques like super-leaps and ceiling suspension. The goal is to collect Eurocheques and plane tickets while avoiding hazards. The game incorporates unique elements such as drunkenness effects from wine bottles and aerial combat sequences. As the third main entry in the Monty Mole series, it builds upon the gameplay mechanics of its predecessors while introducing new challenges and environments.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co91yo.jpg', '1987-12-31', '{8,31}', 'IGDB', 92.1464558134, 13350, 1, 15.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/80513.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/832731.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/832732.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/832733.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/832729.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/832730.jpg"]', '{20342,55173,24426,28070,55190,111130,56033,89597,37001,106987}', '{https://www.youtube.com/watch?v=AMNp5tNQlr4}', 'Gremlin Graphics Software Ltd.', '0', null, '{1747}'), (1128, 'Fuga: Melodies of Steel 2', 'The sequel to the captivating tale of Fuga: Melodies of Steel has arrived! This turn-based RPG is back with a ramped up battle system for more strategy, as well as a brand new event system that gives you more thrilling choices to affect your experience!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co51x6.jpg', '2023-05-11', '{12,13,15,16,24}', 'IGDB', 92.1263732187433, 212264, 1, 66.99, '[{"id":138043,"rating_category":{"id":10,"rating":"12"}},{"id":134488,"rating_category":{"id":21,"rating":"16"}},{"id":134489,"rating_category":{"id":24,"rating":"12+"}},{"id":178045,"rating_category":{"id":14,"rating":"B"}},{"id":134487,"rating_category":{"id":31,"rating":"14"}},{"id":134490,"rating_category":{"id":5,"rating":"T"}},{"id":134486,"rating_category":{"id":36,"rating":"M"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/83426.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/849615.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/849616.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/849617.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/849618.jpg"]', '{36258,13196,26845,102057,8422,103232,7615,109339,25311,112191}', '{https://www.youtube.com/watch?v=OolRShEoq9I,https://www.youtube.com/watch?v=hydneoxIkJ0}', 'CyberConnect2', '0', null, '{8145,2470}'), (1129, 'Zaos', 'International Free to Play Fantasy MMORPG game, featuring incredible journeys through a beautiful expanding world.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lgm.jpg', null, '{12,31}', 'IGDB', 92.0879120879121, 141408, 1, 79.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/410906.jpg"]', '{106987,81249,96217,23651,49414,103168,115653,101608,28010,55038}', '{https://www.youtube.com/watch?v=m0-KktaHWUI}', 'Zaos Entertainment S.A', '0', null, null), (1130, 'Alley Catz Bowling', 'Alley Catz Bowling Was created in 2021 to provide fun to twitch users we are a very simply bowling game that can be controlled by twitch by typing !bowl in chat. Users are able to put a spin on there balls and power to there balls and lot more.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dbk.jpg', '2021-05-27', '{13,14,33}', 'IGDB', 92.0661157024794, 149292, 1, 52.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/247596.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/487251.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/490484.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/490483.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/466372.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/487250.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/466371.jpg"]', '{114286,38967,119422,103218,102805,114287,108759,4642,109606,27378}', '{https://www.youtube.com/watch?v=c5eaLwnDCOQ,https://www.youtube.com/watch?v=9i-rc8t1Te8,https://www.youtube.com/watch?v=S3oAVlIrMSs,https://www.youtube.com/watch?v=AP4bV2PNlkE}', 'Alley Catz', '0', null, null), (1131, 'Unreal Tournament', 'Unreal Tournament is a first-person arena shooter video game developed by Epic Games and Digital Extremes. It was the second installment in the Unreal series.

It is an arena first-person shooter, with head-to-head multiplayer deathmatches being the primary focus of the game. Other game modes include TDM. CTF, Assault, Domination, Last man Standing etc.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2k3b.jpg', '1999-11-22', '{5}', 'IGDB', 92.0642170858193, 272, 1, 12.99, '[{"id":167653,"rating_category":{"id":33,"rating":"18"}},{"id":68526,"rating_category":{"id":6,"rating":"M"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/16714.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/16715.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/309015.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/309014.jpg"]', '{95340,119177,106805,38030,87622,28751,32902,43367,55038,105269}', '{https://www.youtube.com/watch?v=zSvTvZpeD4k,https://www.youtube.com/watch?v=EP-NfrP_GaM}', 'Epic Games', '0', null, '{10121}'), (1132, 'Advance Wars', 'Just because this battle fits in the palm of your hand doesn''t mean the stakes are small. On the contrary, this all-or-nothing fight will have you accessing guns, grenades, launchers, and weaponry of all sorts. Players assume command of an army that''s out to reclaim a world that''s been broken up by warring factions. The battle map is essentially a grid, and moving units is like moving chess pieces on a board -- each of the units can move a specific amount of spaces within this grid, and can only attack at a certain distance from specific enemies. Advance Wars features more than 115 maps, a map editor, head-to-head play via link cable, and an easy-to-understand tutorial mode for beginners.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9nu.jpg', '2001-09-10', '{13,15,16,24}', 'IGDB', 92.0600647940317, 1691, 1, 8.99, '[{"id":8788,"rating_category":{"id":3,"rating":"E"}},{"id":8789,"rating_category":{"id":9,"rating":"7"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/73614.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/20227.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/24682.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/24684.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/24683.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/24685.jpg"]', '{8422,14394,848,1692,58075,276,26845,649,587,19354}', '{https://www.youtube.com/watch?v=cmrncNt9xUA}', 'Nintendo', '0', null, '{335}'), (1133, 'Rocksmith 2014 Edition: Remastered', 'The fastest way to learn guitar is now better than ever. With Rocksmith you can learn everything from single notes to chords and advanced techniques, all at your own pace. You''ll learn fast because it adapts to your skill level as you play, whether you''re a beginner or an experienced player.

This remastered version also includes six free bonus songs.
"Three Little Birds" by Bob Marley & The Wailers
"Suspicious Minds" by Elvis Presley
"Some Nights" by FUN.
"I Want You Back" by Jackson 5
"Hey Ya!" by Outkast
"Drops of Jupiter" by Train', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sgg.jpg', '2016-10-04', '{7,13}', 'IGDB', 92.0366909218877, 30155, 1, 59.99, '[{"id":108149,"rating_category":{"id":36,"rating":"M"}},{"id":108148,"rating_category":{"id":24,"rating":"12+"}},{"id":63233,"rating_category":{"id":5,"rating":"T"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/35549.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/101329.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/101326.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/101327.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/101328.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/101330.jpg"]', '{101573,32688,86847,105264,17613,44178,112754,377651,343492,275468}', '{}', 'Ubisoft Entertainment', '9', '{289007}', null), (1134, 'Master of Orion II: Battle at Antares', 'Master of Orion 2 also known as MOO2 is considered the classic 4x turn based strategy game set in space. The game has a kind of cult status and even by to days standards is still only matched in game play by very few of its competitors.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fhi.jpg', '1996-11-22', '{15,16}', 'IGDB', 92.0306330054856, 68, 1, 9.99, '[{"id":71863,"rating_category":{"id":3,"rating":"E"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/41102.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/78148.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/78152.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/78151.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/78150.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/78149.jpg"]', '{102057,13660,11550,16806,8714,117417,17111,24620,11582,13200}', '{https://www.youtube.com/watch?v=InzmWCqyjZU}', 'Simtex', '0', null, '{80}'), (1135, 'Toontown Rewritten', 'Toontown Rewritten is a free-to-play revival of Disney''s Toontown Online. Toontown is a massively multiplayer online game built for kids, teens, and adults of all ages. Create your own Toon and join the never-ending battle against the "Cogs", who want to turn Toontown into their latest business venture.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9sbj.jpg', '2017-09-01', '{12,16,31}', 'IGDB', 92.0191540303272, 134488, 1, 40.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1529258.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1529246.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1529259.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1529256.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1529247.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1529249.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1529250.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1529252.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1529253.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1529254.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1529248.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1529245.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1529251.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1529255.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1529257.jpg"]', '{19164,115653,81249,103303,27209,113360,105049,96217,106987,17548}', '{https://www.youtube.com/watch?v=9KF8MSJsAxs,https://www.youtube.com/watch?v=Y22poSvMCsc,https://www.youtube.com/watch?v=oGuILC8u5rA,https://www.youtube.com/watch?v=z3mAxF2gfAg,https://www.youtube.com/watch?v=EfwYiAkQjM0,https://www.youtube.com/watch?v=tKx32qWfbGU,https://www.youtube.com/watch?v=j4aFVlIjjlc,https://www.youtube.com/watch?v=oLmzui5STfE,https://www.youtube.com/watch?v=XRSFvwlEEP4}', 'Toons of the World Foundation', '5', null, null), (1136, 'Dragon Quest VII Reimagined', 'DRAGON QUEST VII Reimagined is a modern remake of DRAGON QUEST VII, which originally launched on PlayStation in 2000. In this new reimagined version of the game, the core concept of the original title remains, but the battle mechanics, graphics and story have all been updated and improved, providing players with a more streamlined and focused experience. In particular, the graphics in the game were completely overhauled from the original, using real-life doll figures for the characters and monsters that were scanned into the game to create stunning hand-crafted visuals. This definitive version of the game is perfect for fans who want to revisit the beloved story or newcomers who are diving into the world for the first time.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobkan.jpg', '2026-02-05', '{12,31}', 'IGDB', 92, 366884, 1, 93.99, '[{"id":219708,"rating_category":{"id":4,"rating":"E10+"}},{"id":219709,"rating_category":{"id":10,"rating":"12"}},{"id":219710,"rating_category":{"id":14,"rating":"B"}},{"id":223536,"rating_category":{"id":35,"rating":"PG"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/241195.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/241196.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/196285.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/196286.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1638012.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1638013.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1638014.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1638015.jpg"]', '{106987,81249,96217,23651,49414,103168,115653,101608,28010,55038}', '{https://www.youtube.com/watch?v=z13aCVkZaaw,https://www.youtube.com/watch?v=Wf6HMdCStmQ,https://www.youtube.com/watch?v=GL2-tty-p4M,https://www.youtube.com/watch?v=FJBuWsCh_yo}', 'Square Enix', '8', null, '{7988}'), (1137, 'Super Mario Galaxy + Super Mario Galaxy 2', 'Travel the stars with Mario in enhanced versions of these beloved adventures.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coavv6.jpg', '2025-10-02', '{8,31}', 'IGDB', 92, 366878, 1, 83.99, '[{"id":219703,"rating_category":{"id":3,"rating":"E"}},{"id":219704,"rating_category":{"id":9,"rating":"7"}},{"id":219705,"rating_category":{"id":13,"rating":"A"}},{"id":219706,"rating_category":{"id":34,"rating":"G"}},{"id":222117,"rating_category":{"id":23,"rating":"ALL"}},{"id":222118,"rating_category":{"id":19,"rating":"6"}},{"id":222119,"rating_category":{"id":28,"rating":"L"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/197029.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1644006.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1644008.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1644007.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1644009.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1644010.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1644011.jpg"]', '{28070,55038,105269,25311,107318,103301,20342,55173,24426,115283}', '{https://www.youtube.com/watch?v=IIAJU_X8Cjo,https://www.youtube.com/watch?v=6qR7JU33Ao4,https://www.youtube.com/watch?v=rmwOnsJoj8M,https://www.youtube.com/watch?v=tTYux25TW8Q}', 'Nintendo Software Technology', '3', null, null), (1138, 'Seven Knights Re:Birth', '100 Million Hearts, A Legacy Reborn! - Seven Knights Re:BIRTH

Seven Knights Re:BIRTH - an adventure filled role playing game!

Seven Knights is Netmarble’s flagship IP that has surpassed 100 million cumulative downloads and has received immense love and support from fans around the world.

Over the past 11 years, the Seven Knights IP has maintained strong popularity through its robust lineup of titles with diverse gameplay, including Seven Knights, Seven Knights 2, Seven Knights Idle Adventure, and more.

Developed by Netmarble Nexus, the newest entry in the franchise, Seven Knights Re:BIRTH was launched in Korea on May 15, 2025. Built on the accumulated heroes, lore, and expertise in the franchise, Seven Knights Re:BIRTH achieved remarkable success by ranking No.1 on both major mobile app stores in Korea just five days after launch.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coagvg.jpg', '2025-09-18', '{12}', 'IGDB', 92, 366551, 1, 89.99, '[{"id":226672,"rating_category":{"id":5,"rating":"T"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/195858.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/195859.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/195863.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/195864.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/195865.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/195861.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/195862.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/196912.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1639990.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1639991.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1636445.jpg"]', '{19404,23651,49414,54775,106987,96217,115653,99118,19164,26765}', '{https://www.youtube.com/watch?v=CPuN9UpHwCQ,https://www.youtube.com/watch?v=IF0mdYumfcg,https://www.youtube.com/watch?v=Vtng8aKUU4U,https://www.youtube.com/watch?v=vWGBuBvXAs0,https://www.youtube.com/watch?v=J1qg1tEa614}', 'Netmarble', '8', null, '{7999}'), (1139, 'Concierge', 'Concierge is a challenging, suspenseful nonlinear adventure about an old man and an older hotel. Discover your identity and explore your purpose in a surrealistic world of puzzles and trials of every sort. You''re on your own - but you are not alone.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coabbo.jpg', '2025-09-16', '{31,32}', 'IGDB', 92, 359888, 1, 90.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/185277.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/185278.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1605802.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1605803.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1605804.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1605805.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1605808.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1605806.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1605807.jpg"]', '{55282,111130,87975,29348,13189,27266,26223,118637,106987,113402}', '{https://www.youtube.com/watch?v=8X5SoCc0fZQ}', 'Digital Tribe Games', '0', null, null), (1140, 'Hide The Corpse', 'Hide the Corpse is a VR physics-based game where players must hide a body within four minutes across six distinct environments, including a zero-gravity spaceship and an underwater shipwreck.

With quirky humor and immersive gameplay, players will face chaotic fun as they erase evidence and solve creative puzzles. Now featuring a sandbox mode, unlockable levels, and hilarious character skins, Hide the Corpse delivers fast-paced thrills and endless laughs.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8vwa.jpg', '2024-09-17', '{9,13,33}', 'IGDB', 92, 306936, 1, 70.99, '[{"id":216680,"rating_category":{"id":5,"rating":"T"}},{"id":187209,"rating_category":{"id":8,"rating":"3"}},{"id":187208,"rating_category":{"id":3,"rating":"E"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/183142.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/183143.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1402274.jpg"]', '{112078,56033,25905,37419,90788,105011,25646,78550,36553,19164}', '{https://www.youtube.com/watch?v=sc8uFI3XNB0,https://www.youtube.com/watch?v=o9_UyCC6xhs,https://www.youtube.com/watch?v=PPPd1DkSrrw}', 'Realcast', '0', '{380564}', null), (1141, 'Shadow Gambit: Zagan''s Ritual', '"Zagan the Apostate" is inviting you to his ominous laboratory. Recruit the zealous scientist and former Inquisition member to your crew, set sail to an eldritch castle island and experience a new campaign. Will you unveil the secrets of the Inquisition''s holy flame?', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7h59.jpg', '2023-12-06', '{12,15,24,31,32}', 'IGDB', 92, 279542, 1, 56.99, '[{"id":202018,"rating_category":{"id":11,"rating":"16"}},{"id":175978,"rating_category":{"id":36,"rating":"M"}},{"id":175980,"rating_category":{"id":31,"rating":"14"}},{"id":175981,"rating_category":{"id":20,"rating":"12"}},{"id":175983,"rating_category":{"id":5,"rating":"T"}},{"id":175982,"rating_category":{"id":25,"rating":"15+"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/124694.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1205919.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1205915.jpg","https://images.i