tube.com/watch?v=ldr0bg3S6MY,https://www.youtube.com/watch?v=d9gRvP9daPg,https://www.youtube.com/watch?v=3KgmY5NrEzU,https://www.youtube.com/watch?v=H-sFdMgJ93M,https://www.youtube.com/watch?v=xYKt-HRalUU,https://www.youtube.com/watch?v=_0VdUBtrcdA,https://www.youtube.com/watch?v=WMeHjYlRi14,https://www.youtube.com/watch?v=B3z1Gkud9Cc}', 'People Can Fly', '0', '{90660}', null), (1499, 'Fortnite OG', 'FORTNITE OG is BACK and here to stay. Drop into Chapter 1 and explore the OG map, collect OG loot, and relive OG gameplay.

THE OG OG RETURNS Solos or Squads, drop into battle with Fortnite OG: Chapter 1. Build your way to pure victory in Battle Royale or dominate the Island in a new way with Zero Build. Each Fortnite OG season runs approximately two months, bringing back the legendary loot and features from back in the day.

CLASSIC COOL IN THE OG PASS The Fortnite OG Pass features 45 tiers of retro rewards with a modern twist on items and Outfits. A new OG Pass will be available every OG season for 950 V-Bucks or in Fortnite Crew including the OG Pass, new Battle Royale, Music and LEGO Passes in Fortnite Crew for 1,400 V-Bucks. Getting this add-on is not necessary to access this content.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co94re.jpg', '2024-12-06', '{5,12,13,15,31}', 'IGDB', 75.5, 324915, 1, 67.99, '[{"id":194513,"rating_category":{"id":36,"rating":"M"}},{"id":194511,"rating_category":{"id":20,"rating":"12"}},{"id":194510,"rating_category":{"id":30,"rating":"12"}},{"id":194512,"rating_category":{"id":24,"rating":"12+"}},{"id":194508,"rating_category":{"id":15,"rating":"C"}},{"id":194631,"rating_category":{"id":5,"rating":"T"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/150188.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1432634.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1432635.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1432630.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1432631.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1432632.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1432636.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1432637.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1432638.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1432639.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1432633.jpg"]', '{26574,17379,44076,19164,109339,25311,35994,17548,10776,37419}', '{https://www.youtube.com/watch?v=lGBAi0rKczk,https://www.youtube.com/watch?v=qIxERu81HVI}', 'Epic Games', '2', null, null), (1500, 'Fortnite Reload', 'Fortnite Reload is a 40-player fast-paced Battle Royale game that is all about carrying the squad to Victory. Reboot as long as one teammate is still in the action! Loot up after rebooting to get back into fighting shape! Eliminate opponents to reboot teammates faster! Near the end of the match, reboots will stop. Lock in with your squad to secure the Victory Royale!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9giw.jpg', '2024-06-22', '{5,12,13,15,31}', 'IGDB', 75.5, 324921, 1, 65.99, '[{"id":194522,"rating_category":{"id":10,"rating":"12"}},{"id":194527,"rating_category":{"id":36,"rating":"M"}},{"id":194526,"rating_category":{"id":30,"rating":"12"}},{"id":194521,"rating_category":{"id":5,"rating":"T"}},{"id":194523,"rating_category":{"id":15,"rating":"C"}},{"id":194524,"rating_category":{"id":20,"rating":"12"}},{"id":194525,"rating_category":{"id":24,"rating":"12+"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/215177.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/215179.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/215175.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/215176.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/215178.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/215180.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/215181.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/215182.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/215183.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/215184.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/215185.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/215186.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/215187.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/215188.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/215189.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1432663.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1432665.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1432664.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1432666.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1687787.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1687789.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1687791.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1687793.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1687786.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1687788.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1687790.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1687792.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1687794.jpg"]', '{26574,17379,44076,19164,109339,25311,35994,17548,10776,37419}', '{https://www.youtube.com/watch?v=hkze-xcMN6A}', 'Epic Games', '2', null, null), (1501, 'Fortnite Festival', 'Play in a band with friends or perform solo on stage with hit music by your favorite artists in Fortnite Festival! On the Main Stage, play a featured rotation of Jam Tracks. Compete against friends for the best performance or team up to climb the leaderboards. The festival is just beginning with more Jam Tracks, Music Icons, concerts, and stages coming soon. Take your stage in Fortnite Festival!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaskc.jpg', '2023-12-09', '{7}', 'IGDB', 66.2151217252798, 279764, 1, 57.99, '[{"id":162158,"rating_category":{"id":36,"rating":"M"}},{"id":214668,"rating_category":{"id":10,"rating":"12"}},{"id":162153,"rating_category":{"id":5,"rating":"T"}},{"id":162155,"rating_category":{"id":24,"rating":"12+"}},{"id":162156,"rating_category":{"id":30,"rating":"12"}},{"id":162157,"rating_category":{"id":20,"rating":"12"}},{"id":173143,"rating_category":{"id":15,"rating":"C"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/124935.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/215327.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/260139.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/260140.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/260141.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1207075.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1207074.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1207073.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1316926.jpg"]', '{63933,77720,18981,331127,331011,330988,266558,239849,233959,167281}', '{https://www.youtube.com/watch?v=GtNrQb_gbFU}', 'Harmonix Music Systems', '2', null, null), (1502, 'Fortnite: Season 5', 'Drop into Season 5, where we’re introducing all kinds of changes to the map! A viking ship, desert outpost, and ancient statues have appeared on the island, changing the world of Fortnite as we know it. On top of that, Fortnite’s first four person vehicle has arrived! Hop in a zippy ATK (All Terrain Kart) with your squad and uncover all new mysteries and locations, the possibilities are endless!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z2b.jpg', '2018-07-12', '{5}', 'IGDB', 72.7166465135026, 129875, 1, 33.99, '[{"id":27120,"rating_category":{"id":10,"rating":"12"}},{"id":27119,"rating_category":{"id":5,"rating":"T"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/8544.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/61940.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/366934.jpg"]', '{95340,47823,26574,68287,18290,37419,119177,38030,17548,106805}', '{https://www.youtube.com/watch?v=hgZz911mFB8,https://www.youtube.com/watch?v=F3UNnrr1pg4,https://www.youtube.com/watch?v=kvfqMOyJDQY}', 'Epic Games', '7', null, null), (1503, 'Fortnite: Season 9', 'The volcano has erupted and forever changed some long lasting locations - from the ashes, Neo Tilted rises. Grab the squad to explore the bright lights of new attractions like Peely’s Banana Stand and Nugget Hut. Catch a ride and quickly traverse areas by flying in and out of the new Slipstream wind transportation system. Use the new Air Vents to quickly navigate from building to building. Take a glide over to the new Mega Mall to do some shopping before the storm hits. The future is yours in Season 9!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z27.jpg', '2019-05-09', '{5}', 'IGDB', 36.6666666666667, 129871, 1, 37.99, '[{"id":27111,"rating_category":{"id":5,"rating":"T"}},{"id":27112,"rating_category":{"id":10,"rating":"12"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/8534.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/8535.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/61939.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/365532.jpg"]', '{95340,47823,26574,68287,18290,37419,119177,38030,17548,106805}', '{https://www.youtube.com/watch?v=n4YkqKCp2DQ,https://www.youtube.com/watch?v=Y__AysHzUWo}', 'Epic Games', '7', null, null), (1504, 'Fortnite: Season 6', 'Are you daring enough to enter the Wailing Woods, face the corruption of the cube or visit the Haunted Castle? The corrupted areas have spawned Shadow Stones around the island. Consume them to uncover their power.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z2a.jpg', '2018-09-27', '{5}', 'IGDB', 62.5, 129874, 1, 35.99, '[{"id":27118,"rating_category":{"id":10,"rating":"12"}},{"id":27117,"rating_category":{"id":5,"rating":"T"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/8541.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/8542.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/366721.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/366720.jpg"]', '{95340,47823,26574,68287,18290,37419,119177,38030,17548,106805}', '{https://www.youtube.com/watch?v=xAtebIYU85U,https://www.youtube.com/watch?v=DQbUQay7Fyo}', 'Epic Games', '7', null, null), (1505, 'Fortnite: Season 4', 'Season 4 is starting off with a BANG. Shards of a massive comet have crashed into the map altering the landscape. Discover gravity-defying Hop Rocks and find new ways to play. Jump in and witness the aftermath of the impact while you level up your Battle Pass and earn all new loot.

The Season 4 Battle Pass is here sporting 100 tiers of awesome new rewards, including new cosmetic items, emotes and Sprays.

Start a movie marathon in Save the World’s latest questline, Blockbuster! Part 1 starts with Five quests and one Landmark Mission. Ray has gone missing and no one knows where she is. With the help of Spitfire and Lok, investigate the comet and gear up to recruit a team of superheroes. Find Ray and bring her back home!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z2c.jpg', '2018-05-01', '{5}', 'IGDB', 71.6216216216216, 129876, 1, 49.99, '[{"id":27121,"rating_category":{"id":5,"rating":"T"}},{"id":27122,"rating_category":{"id":10,"rating":"12"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/8545.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/367166.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/367165.jpg"]', '{95340,47823,26574,68287,18290,37419,119177,38030,17548,106805}', '{https://www.youtube.com/watch?v=fDRrqJU4-Tk,https://www.youtube.com/watch?v=3uXOqbic2xg}', 'People Can Fly', '7', null, null), (1506, 'Fortnite: Season 8', 'Season 8 has arrived and a monstrous volcano has appeared! Freed from the Ice King’s castle, the now-powerful Prisoner has brought fire and flame to Fortnite and its islands. Pirates, Ninjas and a ship load of new fighters will tussle over treasure, battle with Pirate Cannons and uncover legendary loot. For those daring enough to explore, the new Lazy Lagoon and Sunny Steps locations are just a jump away with the help of Volcanic Vents. There are tons of new areas to explore and secrets to uncover. This season, X marks the spot!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z28.jpg', '2019-02-28', '{5}', 'IGDB', 56.2308647083161, 129872, 1, 56.99, '[{"id":27113,"rating_category":{"id":5,"rating":"T"}},{"id":27114,"rating_category":{"id":10,"rating":"12"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/8537.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/8538.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/61941.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/366010.jpg"]', '{95340,47823,26574,68287,18290,37419,119177,38030,17548,106805}', '{https://www.youtube.com/watch?v=HoFNer6dqi8}', 'Epic Games', '7', null, null), (1507, 'Fortnite: Season 1', 'Season 1 was the first iteration of player progression in Battle Royale. Players could buy 4 Items in the Item Shop after earning enough XP. It started on October 26th 2017 and concluded on December 13th 2017.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coatd3.jpg', '2017-10-25', '{5}', 'IGDB', 75.5, 256925, 1, 51.99, '[{"id":146441,"rating_category":{"id":10,"rating":"12"}},{"id":146440,"rating_category":{"id":5,"rating":"T"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/205074.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1089752.jpg"]', '{95340,47823,26574,68287,18290,37419,119177,38030,17548,106805}', '{}', 'Epic Games', '7', null, null), (1508, 'Fortnite: Season 7', 'Season 7 has arrived with the smash of a mysterious iceberg! Winter has brought many changes to the Fortnite map for you to explore. Ziplines are a new way to help you travel to and from high terrain. For you chill and thrill seekers, the new Frosty Flights location and Expedition outposts are outfitted with the new Stormwing planes so you can take to the skies. There are tons of new areas to venture to and secrets to uncover, so stay frosty.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z29.jpg', '2018-12-06', '{5}', 'IGDB', 63.0875352181094, 129873, 1, 45.99, '[{"id":27116,"rating_category":{"id":10,"rating":"12"}},{"id":27115,"rating_category":{"id":5,"rating":"T"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/8539.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/8540.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/366352.jpg"]', '{95340,47823,26574,68287,18290,37419,119177,38030,17548,106805}', '{https://www.youtube.com/watch?v=Fm9L1NosXps,https://www.youtube.com/watch?v=LiJ5nIB7Aik}', 'Epic Games', '7', null, null), (1509, 'Fortnite: Season 3', 'The storyline began around this season with players spotting a comet (later revealed to be a meteor) in the sky. Many players speculated that the meteor would hit and destroy Tilted Towers, and it did, destroying one of the central buildings by a small meteor. As Season 4 begins, a big meteor got rid of Dusty Depot and turning it into Dusty Divot.

The game''s user base increased around this season.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z2d.jpg', '2018-02-22', '{5}', 'IGDB', 69.9800995024876, 129877, 1, 47.99, '[{"id":27123,"rating_category":{"id":5,"rating":"T"}},{"id":27124,"rating_category":{"id":10,"rating":"12"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/8547.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/8546.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/367173.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/367175.jpg"]', '{95340,47823,26574,68287,18290,37419,119177,38030,17548,106805}', '{https://www.youtube.com/watch?v=jGqDVknzX3o}', 'People Can Fly', '7', null, null), (1510, 'Fortnite: Season 2', 'Season 2 was focused on heraldic imagery: the cosmetic item set Fort Knights featured 11 items that debuted during this period. Season 2 also saw the first great map expansion in Patch 2.2.0. On January 18, 2018 the map saw the addition of 10 new POIs, including locations like Tilted Towers, Shifty Shafts and Snobby Shores. Season 2 also introduced a new feature to replace Season 1''s Season Shop: The Battle Pass.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co30zh.jpg', '2017-12-14', '{5}', 'IGDB', 65.7142857142857, 129878, 1, 33.99, '[{"id":27126,"rating_category":{"id":10,"rating":"12"}},{"id":27125,"rating_category":{"id":5,"rating":"T"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/367347.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/367346.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/367348.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/367345.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/367350.jpg"]', '{95340,47823,26574,68287,18290,37419,119177,38030,17548,106805}', '{https://www.youtube.com/watch?v=Vs9X5vim3vo}', 'Epic Games', '7', null, null), (1511, 'Fortnite: Chapter 3', 'The island from Chapter 2 has been turned upside down... literally. Step onto the new island and explore every corner of an undiscovered world in Fortnite Chapter 3 Season 1: Flipped.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4olj.jpg', '2021-12-05', '{5,12,15}', 'IGDB', 75.5, 183639, 1, 67.99, '[{"id":50647,"rating_category":{"id":10,"rating":"12"}},{"id":85799,"rating_category":{"id":5,"rating":"T"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/704895.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/704894.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/701770.jpg"]', '{26574,19164,17548,17379,44076,10776,8422,47823,95340,37419}', '{https://www.youtube.com/watch?v=knAYcg7Tt8E,https://www.youtube.com/watch?v=Ww9OhgXWW0Q}', 'Epic Games', '7', null, null), (1512, 'Fortnite: Chapter 2', 'Drop into a new world. Choose your landing spot and explore an all new island featuring 13 new locations. Swim, fish and more! Support your squad by using the bandage bazooka and check out the new hideouts and explosives! The combat is also upgraded with less grind and more fun.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z4s.jpg', '2019-10-15', '{5}', 'IGDB', 20, 129880, 1, 35.99, '[{"id":27128,"rating_category":{"id":10,"rating":"12"}},{"id":27127,"rating_category":{"id":5,"rating":"T"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/8570.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/367542.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/367540.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/367541.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/367545.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/367543.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/367544.jpg"]', '{95340,47823,26574,68287,18290,37419,119177,38030,17548,106805}', '{https://www.youtube.com/watch?v=Qv53Wvq_9pk,https://www.youtube.com/watch?v=3KgmY5NrEzU}', 'People Can Fly', '7', null, null), (1513, 'Fortnite: Season X', 'A new Season also means the debut of the Season X Battle Pass. Over 100 exclusive rewards are ready for you to unlock, and it still costs the same 950 V-bucks! This time around, you’ll get the X-Lord and Catalyst Outfits instantly when you purchase the Battle Pass. As you level up, you’ll unlock rewards like dual pickaxes, emotes, loading screens, Outfit styles, and more. At Tier 100, you’ll unlock the hulking Ultima Knight Outfit.

New to this Season''s Battle Pass are Missions! Unlock rewards by completing a series of thematic objectives that will send you on adventures across the Island.

Lastly, is the ability to gift the Battle Pass to a friend!', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z26.jpg', '2019-08-01', '{5}', 'IGDB', 35.1724137931034, 129870, 1, 34.99, '[{"id":27109,"rating_category":{"id":5,"rating":"T"}},{"id":27110,"rating_category":{"id":10,"rating":"12"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/8533.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/8532.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/364749.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/364748.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/364747.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/364746.jpg"]', '{95340,47823,26574,68287,18290,37419,119177,38030,17548,106805}', '{https://www.youtube.com/watch?v=2rUt9qxohRM,https://www.youtube.com/watch?v=2GXHxM6noOc}', 'Epic Games', '7', null, null), (1514, 'Fortnite Ballistic', 'FORTNITE BALLISTIC is a first-person, 5v5 tactical FPS in Early Access. Prove your talents, precision and teamwork to overcome your opponents.

Each round, use your skills and gadgets to Attack and Defend your side. Avoid elimination and outplay your opponents to secure victory for your team.

TACTICAL CHOICES MATTER.
Choose your gadget and lock in! Fortnite Ballistic provides unique, Flex gadgets that can alter the outcome of a round. Once you’ve locked in your gadget, add it to your arsenal during the Buy phase of each round and go ballistic.

FIRST PERSON, FULL IMPACT
Fortnite Ballistic is the first Fortnite mode built using the First Person Camera Mode Device in UEFN. Experience Fortnite in an all new way, challenging your skills and testing your tactics.

Getting this experience is not necessary to access this content. When you launch Fortnite using this through your Library, the experience will be pre-selected for your convenience.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co954d.jpg', '2024-12-11', '{5,13,15}', 'IGDB', 75.5, 325281, 1, 74.99, '[{"id":198641,"rating_category":{"id":15,"rating":"C"}},{"id":198642,"rating_category":{"id":30,"rating":"12"}},{"id":194751,"rating_category":{"id":5,"rating":"T"}},{"id":198643,"rating_category":{"id":20,"rating":"12"}},{"id":198645,"rating_category":{"id":36,"rating":"M"}},{"id":198644,"rating_category":{"id":24,"rating":"12+"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/260129.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/260130.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1434354.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1434355.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1434356.jpg"]', '{95340,26574,8422,36553,109339,19164,25311,35994,103302,17379}', '{https://www.youtube.com/watch?v=wYdar6yxg7E}', 'Epic Games', '2', null, null), (1515, 'Fortnite Festival: I', '', null, null, null, 'IGDB', 75.5, 366638, 1, 79.99, '[]', '[]', '[]', null, '{}', null, '13', null, null), (1516, 'Fortnite: Chapter 4', 'A new beginning awaits.

In the fourth Chapter of Fortnite’s Battle Royale, go forth in a new realm and get around in new ways — ride a dirt bike, roll in a snowball, launch yourself with the Shockwave Hammer, and hurdle over obstacles. Power yourself up with Reality Augments and claim territory for your squad, leaving behind Banners to declare what’s yours. And of course, venture with newly-forged weapons.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co60u5.jpg', '2022-12-04', '{5,12,15}', 'IGDB', 86.7836156859603, 228328, 1, 72.99, '[{"id":107685,"rating_category":{"id":10,"rating":"12"}},{"id":107684,"rating_category":{"id":5,"rating":"T"}}]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/945697.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/945698.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/945699.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/945700.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/945701.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/945702.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/945703.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/945704.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/945705.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/945706.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/945707.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/945708.jpg"]', '{26574,19164,17548,17379,44076,10776,8422,47823,95340,37419}', '{https://www.youtube.com/watch?v=XXYxZySYeFU,https://www.youtube.com/watch?v=JW-KIbV9PRU}', 'Epic Games', '7', null, null), (1517, 'Fortnite Festival: Bum Bum', '', null, null, null, 'IGDB', 75.5, 367583, 1, 79.99, '[]', '[]', '[]', null, '{}', null, '13', null, null), (1518, 'Fortnite Festival: One', '', null, null, null, 'IGDB', 75.5, 367587, 1, 79.99, '[]', '[]', '[]', null, '{}', null, '13', null, null), (1519, 'Fortnite Festival: Fuel', '', null, null, null, 'IGDB', 75.5, 368799, 1, 79.99, '[]', '[]', '[]', null, '{}', null, '13', null, null), (1520, 'Fortnite Festival: Bang Bang', '', null, null, null, 'IGDB', 75.5, 368827, 1, 79.99, '[]', '[]', '[]', null, '{}', null, '13', null, null), (1521, 'LEGO Fortnite: Odyssey', 'Explore vast, open worlds where the magic of LEGO building and Fortnite collide.
​​​​Collect food and resources, craft items​, build shelter and battle enemies solo or​ team up​ with up to seven friends.

​Get creative in building and ​customizing​​​ your ultimate home base​ using LEGO elements collected from the world around you​, then recruit villagers to gather materials and help survive the night. Gear up and drop into deep caves in search of rare resources and hidden areas.

Find the ultimate survival crafting LEGO adventure in Fortnite! The journey is only just beginning with new world building, gameplay features, and more LEGO Style Outfits arriving in updates starting early 2024.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob23e.jpg', '2023-12-07', '{31}', 'IGDB', 66.1873900178663, 279676, 1, 71.99, '[{"id":161987,"rating_category":{"id":20,"rating":"12"}},{"id":161958,"rating_category":{"id":24,"rating":"12+"}},{"id":161966,"rating_category":{"id":4,"rating":"E10+"}},{"id":161986,"rating_category":{"id":30,"rating":"12"}},{"id":161988,"rating_category":{"id":36,"rating":"M"}},{"id":162040,"rating_category":{"id":15,"rating":"C"}},{"id":226596,"rating_category":{"id":9,"rating":"7"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/229195.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/260137.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/260138.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1207117.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1207115.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1207111.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1207112.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1207113.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1207114.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1207116.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1207118.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1207119.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1207120.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1721383.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1721384.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1721385.jpg"]', '{37419,26574,81249,17548,19164,105011,10776,111130,103261,47823}', '{https://www.youtube.com/watch?v=FRxbjqKAgHE,https://www.youtube.com/watch?v=GeKTrjGdJ2E,https://www.youtube.com/watch?v=AZAuqt_AvYY,https://www.youtube.com/watch?v=UYzJvHNmC6A}', 'Epic Games', '2', null, null), (1522, 'Fortnite: Lok-Bot Pack', 'Imagine, if you will, an oven bot and the places he will go. Grab the Lok-Bot Pack featuring:

- Access to “Save the World” PvE Campaign
- Lok-Bot Hero
- Lok-Bot Outfit (usable in Battle Royale & Creative)
- Lok Block Back Bling (usable in Battle Royale & Creative)
- Lok Pick Pickaxe (usable in Battle Royale & Creative)
- Lok-Bot Challenges: Earn up to 1,000 V-Bucks and 1,000 X-Ray Tickets by completing Save the World daily quests.

Rewards distributed after having completed the "Homebase Stormshield Defense 1" mission in "Save the World" Campaign.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaclp.jpg', '2021-06-22', '{5}', 'IGDB', 75.5, 227082, 1, 53.99, '[]', '[]', '[]', '{95340,38030,32902,119177,106805,87622,103302,43367,95308,520}', '{}', 'Epic Games', '13', null, null), (1523, 'Fortnite Festival: Miku', '', null, null, null, 'IGDB', 75.5, 370638, 1, 79.99, '[]', '[]', '[]', null, '{}', null, '13', null, null), (1524, 'Fortnite Festival: Dare', '', null, null, null, 'IGDB', 75.5, 366372, 1, 79.99, '[]', '[]', '[]', null, '{}', null, '13', null, null), (1525, 'Fortnite Festival: Toxic', '', null, null, null, 'IGDB', 75.5, 366643, 1, 79.99, '[]', '[]', '[]', null, '{}', null, '13', null, null), (1526, 'Fortnite Festival: Zombie', '', null, null, null, 'IGDB', 75.5, 366397, 1, 79.99, '[]', '[]', '[]', null, '{}', null, '13', null, null), (1527, 'Fortnite: Airphoria Pack', '', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6w6j.jpg', '2023-06-23', '{5}', 'IGDB', 75.5, 260134, 1, 75.99, '[]', '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1108554.jpg"]', null, '{}', 'Epic Games', '13', null, null), (1528, 'Fortnite Festival: Closer', '', null, null, null, 'IGDB', 75.5, 371635, 1, 79.99, '[]', '[]', '[]', null, '{}', null, '13', null, null), (1529, 'Fortnite: Band Flair Pack', 'This is a Rare Limited Time Offer exclusive to PlayStation Plus subscribers. Players could obtain the pack by:
• Subscribing to PlayStation Plus
• Redeeming the offer in the PlayStation Store
The pack was released during Fortnite Chapter 5: Season 4 and was specifically designed for PlayStation Plus members.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coafeg.jpg', '2024-08-21', '{5,12,13,15,31}', 'IGDB', 75.5, 315993, 1, 79.99, '[]', '[]', '[]', null, '{}', 'Epic Games', '13', null, null), (1530, 'Fortnite Festival: Redrum', '', null, null, null, 'IGDB', 75.5, 366648, 1, 79.99, '[]', '[]', '[]', null, '{}', null, '13', null, null), (1531, 'LEGO Fortnite: Brick Life', 'Build your new life in an ever-evolving LEGO city.

Experience a highly social destination for up to 32 players where you can explore all the city has to offer!

Be the ultimate socialite and hang out in restaurants, house parties or rooftop clubs. Chat with friends or make new ones, activities in LEGO Fortnite Brick Life are better together. Host a band practice down the beach, grab a bite to eat with others or race through the streets on hover boards.

Take on a job, complete tasks to earn some spending money and start living the life in Brick Bay with vehicles, housing and more. Customize your home with furnishings from the local store or invite your friends over to hang out.

Getting this experience is not necessary to access this content. When you launch Fortnite using this through your Library, the experience will be pre-selected for your convenience.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95dd.jpg', '2024-12-12', '{13,31}', 'IGDB', 75.5, 325544, 1, 73.99, '[{"id":202651,"rating_category":{"id":36,"rating":"M"}},{"id":202650,"rating_category":{"id":24,"rating":"12+"}},{"id":202649,"rating_category":{"id":20,"rating":"12"}},{"id":202648,"rating_category":{"id":30,"rating":"12"}},{"id":202646,"rating_category":{"id":15,"rating":"C"}},{"id":232416,"rating_category":{"id":4,"rating":"E10+"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/260135.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/260136.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1435826.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1435827.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1435828.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1435829.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1435830.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1435831.jpg"]', '{37419,26574,19164,105011,81249,17548,25311,35994,10776,113360}', '{https://www.youtube.com/watch?v=KoF7Xfp-ako}', 'Epic Games', '2', null, null), (1532, 'Fortnite: Sun & Scales Pack', 'Starter bundle offering cosmetic gear, a LEGO-themed version of the main outfit, and in-game currency. Launched mid‑season in Chapter 5 Season 4 and available only via real-money purchase for a limited period.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa9fj.jpg', '2024-08-21', '{5,12,13,15,31}', 'IGDB', 75.5, 318648, 1, 66.99, '[]', '[]', '[]', '{26574,17379,44076,19164,109339,25311,35994,17548,10776,37419}', '{}', 'Epic Games', '13', null, null), (1533, 'Fortnite Festival: I Wish', '', null, null, null, 'IGDB', 75.5, 369067, 1, 79.99, '[]', '[]', '[]', null, '{}', null, '13', null, null), (1534, 'Fortnite: Save the World', 'Discover the epic PvE action-building co-op campaign. Take on the monster hordes either solo or with up to three friends as you explore a vast, destructible world, with dynamically created maps where no two games are ever the same.

Build & Defend: Construct elaborate trap tunnels and towering fortresses to protect your objectives from relentless waves of monsters.

Loot & Craft: Scavenge the environment for materials to craft legendary weapons, from neon scythes to heavy-duty rocket launchers.

Level Up: Rescue, recruit and customize a massive roster of Heroes from one of four classes - Soldiers, Ninjas, Outlanders, and Constructors - to suit your playstyle.

The fight is on. Gather your squad, find your favorite gear, and Save the World.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobw1c.jpg', '2026-04-16', '{5}', 'IGDB', 75.5, 395833, 1, 92.99, '[]', '["https://images.igdb.com/igdb/image/upload/t_1080p/265112.jpg"]', '["https://images.igdb.com/igdb/image/upload/t_1080p/1814306.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1814307.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1814308.jpg","https://images.igdb.com/igdb/image/upload/t_1080p/1814309.jpg"]', '{83727,58095,95340,369790,340994,150744,127050,119177,38030,106805}', '{https://www.youtube.com/watch?v=fRsGaPkRv3o}', 'Epic Games', '2', null, null), (1535, 'Fortnite Festival: Sucker', '', null, null, null, 'IGDB', 75.5, 366810, 1, 79.99, '[]', '[]', '[]', null, '{}', null, '13', null, null), (1536, 'Fortnite Festival: Song 2', '', null, null, null, 'IGDB', 75.5, 366803, 1, 79.99, '[]', '[]', '[]', null, '{}', null, '13', null, null), (1537, 'Fortnite Festival: Unholy', '', null, null, null, 'IGDB', 75.5, 366564, 1, 79.99, '[]', '[]', '[]', null, '{}', null, '13', null, null), (1538, 'Fortnite Festival: Poison', '', null, null, null, 'IGDB', 75.5, 372151, 1, 79.99, '[]', '[]', '[]', null, '{}', null, '13', null, null), (1539, 'Fortnite: Cross Comms Pack', 'When Tegan is on comms, she never misses a callout. Clear, concise and to the point with the Cross Comms pack. Includes 1 Outfit, 1 Back Bling, 1 Pickaxe and 600 V-Bucks.', 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6be0.jpg', '2023-03-20', null, 'IGDB', 75.5, 243231, 1, 51.99, '[{"id":131893,"rating_category":{"id":36,"rating":"M"}},{"id":131894,"rating_category":{"id":10,"rating":"12"}},{"id":131897,"rating_category":{"id":20,"rating":"12"}},{"id":131896,"rating_category":{"id":24,"rating":"12+"}},{"id":131898,"rating_category":{"id":5,"rating":"T"}},{"id":131895,"rating_category":{"id":30,"rating":"12"}}]', '["https://images.igdb.com/igdb/image/upload/t_1080p/104401